INSERT INTO `site_settings` (`id`, `site_name_th`, `site_name_en`, `site_title_suffix_th`, `site_title_suffix_en`, `default_meta_title_th`, `default_meta_title_en`, `default_meta_description_th`, `default_meta_description_en`, `default_og_image_url`, `default_og_image_alt_th`, `default_og_image_alt_en`, `favicon_url`, `default_locale`, `timezone_name`, `line_official_url`, `facebook_url`, `instagram_url`, `shopee_url`) VALUES
  (1, '168 Innovative', '168 Innovative', NULL, NULL, '168 Innovative', '168 Innovative', '168 Innovative Co., Ltd. ผู้นำเข้าและจัดจำหน่ายบรรจุภัณฑ์เครื่องสำอาง ขวดปั๊ม กระปุกครีม และผลิตภัณฑ์พลาสติกสำหรับแบรนด์ OEM พร้อมบริการจัดหาสินค้าและควบคุมคุณภาพจากโรงงานผู้ผลิต', '168 Innovative Co., Ltd. is a trusted importer and distributor of cosmetic packaging and plastic containers for OEM brands, providing high-quality packaging solutions and reliable supply chains.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/logo.png', '168 Innovative', '168 Innovative', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/logo.png', 'th', 'Asia/Bangkok', 'https://line.me/ti/p/~168innovative', 'https://www.facebook.com/profile.php?id=61558620009617', NULL, 'https://shopee.co.th/shop/1240917079');
INSERT INTO `page_seo` (`page_key`, `title_th`, `title_en`, `description_th`, `description_en`, `canonical_path_th`, `canonical_path_en`, `og_image_url`, `og_image_alt_th`, `og_image_alt_en`, `robots_index`, `robots_follow`) VALUES
  ('about', 'เกี่ยวกับเรา | 168 Innovative', 'about us | 168 Innovative', '168 Innovative Co., Ltd. ผู้นำเข้าและจัดจำหน่ายบรรจุภัณฑ์เครื่องสำอาง ขวดปั๊ม กระปุกครีม และผลิตภัณฑ์พลาสติกสำหรับแบรนด์ OEM พร้อมบริการจัดหาสินค้าและควบคุมคุณภาพจากโรงงานผู้ผลิต', '168 Innovative Co., Ltd. is a trusted importer and distributor of cosmetic packaging and plastic containers for OEM brands, providing high-quality packaging solutions and reliable supply chains.', 'https://168innovative.co.th/about', 'https://168innovative.co.th/en/about', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/factory.png', 'กระบวนการคัดเลือกและตรวจสอบคุณภาพบรรจุภัณฑ์', 'Warehouse and packaging inventory management system', 1, 1),
  ('category:spout', 'จุกซอง จุกติดซอง พลาสติก OEM | 168 Innovative', 'Plastic Spout Caps OEM Manufacturer Thailand | 168 Innovative', 'จุกซองพลาสติก จุกติดซอง วัสดุ HDPE คุณภาพสูง \nเหมาะสำหรับเครื่องสำอาง อาหาร และของเหลว \nรับผลิต OEM/ODM จำนวนมาก ส่งทั่วไทยและส่งออก \nติดต่อขอใบเสนอราคาได้เลย', 'High-quality HDPE plastic spout caps for cosmetic, food, and \nliquid flexible pouch packaging. OEM/ODM manufacturing. \nBulk orders available. Request a quote today.', 'https://168innovative.co.th/categories/spout', 'https://168innovative.co.th/en/categories/spout', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/sm04.webp', 'จุกซอง', 'Spout Caps', 1, 1),
  ('category:dispensing-press-cap', 'ฝากด ฝาพลาสติกแบบกด สำหรับขวด OEM | 168 Innovative', 'Dispensing Press Cap for Bottles OEM Thailand | 168 Innovative', 'ฝากด ฝาพลาสติกแบบกด สำหรับขวดครีม โลชั่น เจล ใช้งานง่าย ควบคุมปริมาณได้แม่นยำ รับผลิต OEM/ODM ส่งทั่วไทย', 'Dispensing press caps for cream, lotion, and gel bottles. One-handed operation with precise output control. OEM/ODM manufacturing in Thailand. Request a quote.', 'https://168innovative.co.th/categories/dispensing-press-cap', 'https://168innovative.co.th/en/categories/dispensing-press-cap', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/dispensing-cap.webp', 'ฝากด ฝาพลาสติกแบบกด OEM สำหรับขวดครีมและโลชั่น', 'ฝากด ฝาพลาสติกแบบกด OEM สำหรับขวดครีมและโลชั่น', 1, 1),
  ('category:lipstick-packaging', 'แพ็กเกจลิปสติก หลอดลิปสติก OEM | 168 Innovative', 'Lipstick Packaging & Tube OEM Thailand | 168 Innovative', 'แพ็กเกจลิปสติก หลอดลิปสติก OEM/ODM คุณภาพสูง พลาสติกและอะลูมิเนียม รับผลิตตามแบบสำหรับแบรนด์เครื่องสำอาง สั่งจำนวนมาก', 'Premium lipstick tubes and packaging for OEM/ODM cosmetic brands. Plastic and aluminum options. Custom design manufacturing in Thailand.', 'https://168innovative.co.th/categories/lipstick-packaging', 'https://168innovative.co.th/en/categories/lipstick-packaging', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/lipstick_bottles.webp', 'แพ็กเกจลิปสติก หลอดลิปสติก OEM สำหรับแบรนด์เครื่องสำอาง', 'Lipstick Packaging Tube OEM for Cosmetic Brands Thailand', 1, 1),
  ('category:mascara-packaging', 'บรรจุภัณฑ์มาสคาร่า หลอดมาสคาร่า OEM | 168 Innovative', 'Mascara Packaging & Tube OEM Manufacturer Thailand | 168 Innovative', 'บรรจุภัณฑ์มาสคาร่า หลอดมาสคาร่า OEM/ODM คุณภาพสูง สำหรับแบรนด์เครื่องสำอาง หลากหลายรูปแบบ รับผลิตตามแบบ สั่งจำนวนมาก', 'High-quality mascara tubes and packaging for cosmetic OEM/ODM brands. Custom design and manufacturing in Thailand. Multiple styles available.', 'https://168innovative.co.th/categories/mascara-packaging', 'https://168innovative.co.th/en/categories/mascara-packaging', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/mascaras.webp', 'บรรจุภัณฑ์มาสคาร่า หลอดมาสคาร่า OEM สำหรับแบรนด์เครื่องสำอาง', 'Mascara Packaging Tube OEM for Cosmetic Brands Thailand', 1, 1),
  ('category:powder-compact', 'ตลับแป้งพัฟ ตลับแป้ง กล่องแป้ง OEM สำหรับแบรนด์เครื่องสำอาง | 168 Innovative', 'Compact Powder Case OEM Cosmetic Packaging | 168 Innovative', 'ตลับแป้ง กล่องแป้งพัฟ บรรจุภัณฑ์เครื่องสำอาง OEM/ODM คุณภาพสูง เหมาะสำหรับแป้งอัดแข็ง บลัชออน ไฮไลท์ รับผลิตตามแบบ สั่งจำนวนมาก', 'High-quality compact powder cases for pressed powder, blush, and highlighter. OEM/ODM cosmetic packaging manufacturer in Thailand. Custom design available.', 'https://168innovative.co.th/categories/powder-compact', 'https://168innovative.co.th/en/categories/powder-compact', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/Compact-Powder-Case.webp', 'ตลับแป้ง กล่องแป้งพัฟ OEM สำหรับแบรนด์เครื่องสำอาง', 'Compact Powder Case OEM Cosmetic Packaging Thailand', 1, 1),
  ('category:soap-bag', 'ถุงสบู่ ถุงบรรจุสบู่ OEM หลากหลายวัสดุ | 168 Innovative', 'Soap Bag & Bath Product Packaging OEM Thailand | 168 Innovative', 'ถุงสบู่ ถุงบรรจุสบู่ก้อน สบู่แฮนด์เมด หลากหลายวัสดุ ผ้า ตาข่าย พลาสติก รับผลิต OEM ตามแบบ สั่งจำนวนมาก ราคาส่ง', 'Soap bags and bath product packaging in fabric, mesh, and plastic. OEM custom manufacturing for handmade soap and bath brands. Bulk orders available.', 'https://168innovative.co.th/categories/soap-bag', 'https://168innovative.co.th/en/categories/soap-bag', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/soap-bags.png', 'ถุงสบู่ / ถุงบรรจุภัณฑ์', 'Soap Packaging Bag', 1, 1),
  ('category:ball-chain', 'โซ่ลูกปัด Ball Chain อุปกรณ์เสริมบรรจุภัณฑ์ OEM | 168 Innovative', 'Ball Chain & Packaging Accessories OEM Thailand | 168 Innovative', 'โซ่ลูกปัด ball chain อุปกรณ์เสริมสำหรับบรรจุภัณฑ์ สินค้าพรีเมียม ของขวัญ หลากหลายขนาด รับผลิต OEM ส่งทั่วไทย', 'Ball chains and packaging accessories for premium products, gifts, and jewelry. OEM manufacturing in Thailand. Various sizes available. Request a quote.', 'https://168innovative.co.th/categories/ball-chain', 'https://168innovative.co.th/en/categories/ball-chain', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/ball_chain_cat.webp', 'โซ่ลูกปัด ball chain อุปกรณ์เสริมบรรจุภัณฑ์ OEM', 'Ball Chain Packaging Accessories OEM Thailand', 1, 1),
  ('category:plastic-handle', 'ที่จับพลาสติก หูหิ้ว สำหรับบรรจุภัณฑ์ OEM | 168 Innovative', 'Plastic Handle for Packaging OEM Thailand | 168 Innovative', 'ที่จับพลาสติก หูหิ้วพลาสติก สำหรับถุงและบรรจุภัณฑ์ทุกประเภท ทนทาน น้ำหนักเบา รับผลิต OEM custom size และสี ราคาส่ง', 'Durable plastic handles for bags and packaging. Custom size and color OEM manufacturing available in Thailand. Bulk orders welcome. Request a quote.', 'https://168innovative.co.th/categories/plastic-handle', 'https://168innovative.co.th/en/categories/plastic-handle', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/plastic-handle.webp', 'ที่จับพลาสติก หูหิ้วพลาสติกสำหรับบรรจุภัณฑ์ OEM', 'Plastic Handle for Packaging OEM Thailand', 1, 1),
  ('product:plastic-spout-hl018-1-8mm', 'จุกพลาสติก HL018 ขนาด 1.8 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL018 1.8mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL018 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 1.8 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการควบคุมปริมาณของเหลวอย่างแม่นยำ จุกขนาดเล็กพิเศษนี้ออกแบบมาเพื่อรองรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch สำหรับผลิตภัณฑ์ความหนืดสูง วัสดุ PE ที่ใช้ผลิตมีความยืดหยุ่น ทนทานต่อสารเคมี และปลอดภัยสำหรับการสัมผัสกับผลิตภัณฑ์ดูแลผิว เจล และของเหลวเข้มข้น เหมาะกับอุตสาหกรรมเครื่องสำอาง ยา และผลิตภัณฑ์ดูแลส่วนตัว ตอบโจทย์ผู้ผลิตที่ต้องการบรรจุภัณฑ์มาตรฐานสูงในราคาที่แข่งขันได้ รุ่น HL018 ขนาด 1.8 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL018 plastic spout features an ultra-small inner diameter of 1.8mm, manufactured from high-quality PE material suitable for precision liquid dispensin...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl018-1-8mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl018-1-8mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL018.jpg', 'จุกพลาสติก HL018 ขนาด 1.8 มม. PE สำหรับซองเครื่องสำอาง', 'Plastic Spout HL018 1.8mm PE for Cosmetic Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl020-2mm', 'จุกพลาสติก HL020 ขนาด 2 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL020 2mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL020 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 2 มม. ออกแบบมาสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการจ่ายของเหลวในปริมาณน้อยและแม่นยำ เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ใช้ในอุตสาหกรรมความงามและการดูแลส่วนตัว วัสดุ PE มีความทนทานสูง ปลอดภัยต่อการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท และสามารถผลิตในปริมาณมากได้ตามมาตรฐานอุตสาหกรรม เหมาะสำหรับผู้ผลิตบรรจุภัณฑ์ที่ต้องการโซลูชั่นคุณภาพสูงในราคาที่เหมาะสม รุ่น HL020 ขนาด 2 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL020 plastic spout cap with a 2mm inner diameter is crafted from premium PE material, delivering precise liquid dispensing for cosmetic and beauty pac...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl020-2mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl020-2mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL020.jpg', 'จุกพลาสติก HL020 ขนาด 2 มม. PE สำหรับบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL020 2mm PE for Cosmetic and Beauty Packaging', 1, 1),
  ('product:plastic-spout-hl050-5mm', 'จุกพลาสติก HL050 ขนาด 5 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL050 5mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL050 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะอย่างยิ่งสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวในอุตสาหกรรมความงาม ขนาด 5 มม. ช่วยให้การไหลของของเหลวมีความสม่ำเสมอและควบคุมได้ง่าย เหมาะสำหรับโลชั่น ครีม เซรั่ม และผลิตภัณฑ์ของเหลวที่มีความหนืดปานกลาง วัสดุ PE ทนทานต่อสารเคมีและอุณหภูมิหลากหลาย ตอบสนองความต้องการของผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการบรรจุภัณฑ์มาตรฐานสูงและผลิตได้ในปริมาณมาก รุ่น HL050 ขนาด 5 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL050 plastic spout with a 5mm inner diameter is made from high-quality PE material, offering reliable liquid flow for cosmetic, beauty, and personal c...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl050-5mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl050-5mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL050.jpg', 'จุกพลาสติก HL050 ขนาด 5 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL050 5mm PE for Refill Pouch and Cosmetic Packaging', 1, 1),
  ('product:plastic-spout-h055w-5mm-ldpe', 'จุกพลาสติก H055W ขนาด 5 มม. LDPE | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout H055W 5mm LDPE | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก H055W ผลิตจาก LDPE (Low-Density Polyethylene) มีเส้นผ่านศูนย์กลางภายใน 5 มม. วัสดุ LDPE มีความยืดหยุ่นสูงกว่า PE ทั่วไป เหมาะสำหรับบรรจุภัณฑ์ที่ต้องการความนุ่มนวลในการบีบและการจ่ายผลิตภัณฑ์ ใช้งานได้หลากหลายทั้งในอุตสาหกรรมเครื่องสำอาง อาหาร และผลิตภัณฑ์ดูแลส่วนตัว เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ต้องการวัสดุที่มีความยืดหยุ่นและทนทาน H055W เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับผู้ผลิตที่ต้องการคุณภาพสูงและการใช้งานที่หลากหลาย รุ่น H055W ขนาด 5 มม. วัสดุ LDPE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The H055W plastic spout is manufactured from LDPE (Low-Density Polyethylene) with a 5mm inner diameter, offering superior flexibility compared to standard...', 'https://168innovative.co.th/categories/spout/plastic-spout-h055w-5mm-ldpe', 'https://168innovative.co.th/en/categories/spout/plastic-spout-h055w-5mm-ldpe', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/H055W.jpg', 'จุกพลาสติก H055W ขนาด 5 มม. LDPE สำหรับซองบรรจุของเหลว', 'Plastic Spout H055W 5mm LDPE for Liquid Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl055d-1-5mm', 'จุกพลาสติก HL055D-1 ขนาด 5 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL055D-1 5mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL055D-1 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ความงาม และซองรีฟิลของเหลว รุ่น D-1 มีการออกแบบพิเศษที่เพิ่มประสิทธิภาพการปิดผนึกและการจ่ายผลิตภัณฑ์ เหมาะสำหรับโลชั่น เจล ครีม และผลิตภัณฑ์ของเหลวที่ใช้ในซองแบบ flexible pouch วัสดุ PE ช่วยให้มีความทนทานและความปลอดภัยในการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท เป็นตัวเลือกที่เชื่อถือได้สำหรับผู้ผลิตในอุตสาหกรรม B2B รุ่น HL055D-1 ขนาด 5 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL055D-1 plastic spout cap features a 5mm inner diameter and is made from quality PE material, designed for cosmetic, beauty, and liquid pouch packagin...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl055d-1-5mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl055d-1-5mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL055D-1.jpg', 'จุกพลาสติก HL055D-1 ขนาด 5 มม. PE สำหรับบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL055D-1 5mm PE for Cosmetic Liquid Pouch', 1, 1),
  ('product:plastic-spout-hl050d-5mm', 'จุกพลาสติก HL050D ขนาด 5 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL050D 5mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL050D ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. รุ่น D มีโครงสร้างที่แข็งแรงและออกแบบมาเพื่อการใช้งานในบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์ที่ต้องการจุกปิดที่มั่นคงและการจ่ายของเหลวที่แม่นยำ PE ให้ความทนทานและความปลอดภัยในการสัมผัสกับสารเคมีในผลิตภัณฑ์ความงาม ตอบโจทย์ผู้ผลิตในอุตสาหกรรมบรรจุภัณฑ์ B2B ที่ต้องการคุณภาพและความน่าเชื่อถือในการผลิตปริมาณมาก รุ่น HL050D ขนาด 5 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL050D plastic spout with a 5mm inner diameter is made from PE material, featuring a robust design suited for cosmetic, skincare, and liquid pouch pack...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl050d-5mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl050d-5mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL050D.jpg', 'จุกพลาสติก HL050D ขนาด 5 มม. PE สำหรับซองรีฟิลและเครื่องสำอาง', 'Plastic Spout HL050D 5mm PE for Refill Pouch and Cosmetic Packaging', 1, 1),
  ('product:plastic-spout-hl060l-6mm', 'จุกพลาสติก HL060L ขนาด 6 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL060L 6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL060L ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 6 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองบรรจุของเหลวที่ต้องการอัตราการไหลที่ดีขึ้น รุ่น L มีการออกแบบโครงสร้างที่รองรับการใช้งานอเนกประสงค์ทั้งในอุตสาหกรรมความงาม อาหาร และผลิตภัณฑ์เพื่อครัวเรือน ขนาด 6 มม. ช่วยให้การจ่ายของเหลวมีความคล่องตัวมากขึ้น เหมาะสำหรับผลิตภัณฑ์ที่มีความหนืดปานกลางถึงต่ำ เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับซองรีฟิลและบรรจุภัณฑ์แบบ flexible pouch รุ่น HL060L ขนาด 6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL060L plastic spout cap with a 6mm inner diameter is manufactured from PE material, designed for cosmetic, food, and household liquid pouch packaging...', NULL, NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL060L.jpg', 'จุกพลาสติก HL060L ขนาด 6 มม. PE สำหรับซองบรรจุของเหลว', 'Plastic Spout HL060L 6mm PE for Liquid Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl080d-8mm', 'จุกพลาสติก HL080D ขนาด 8 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL080D 8mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL080D ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองบรรจุของเหลวที่ต้องการการไหลที่รวดเร็วและสม่ำเสมอ ขนาด 8 มม. รองรับผลิตภัณฑ์ที่มีความหนืดสูงขึ้น เช่น แชมพู ครีมนวด โลชั่นบำรุงผิว และผลิตภัณฑ์ทำความสะอาด รุ่น D มีโครงสร้างที่แข็งแรงและป้องกันการรั่วซึมได้ดีเยี่ยม เป็นที่นิยมในอุตสาหกรรม B2B สำหรับการผลิตซองรีฟิลและบรรจุภัณฑ์ flexible pouch ในปริมาณมาก รุ่น HL080D ขนาด 8 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL080D plastic spout with an 8mm inner diameter is produced from PE material, offering efficient liquid dispensing for cosmetic, personal care, and hou...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl080d-8mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl080d-8mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL080D.jpg', 'จุกพลาสติก HL080D ขนาด 8 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์ของเหลว', 'Plastic Spout HL080D 8mm PE for Refill Pouch and Liquid Packaging', 1, 1),
  ('product:plastic-spout-hl060d-sr060-6mm', 'จุกพลาสติก HL060D (SR060) ขนาด 6 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL060D (SR060) 6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL060D หรือที่รู้จักในชื่อ SR060 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 6 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวในอุตสาหกรรมความงามและการดูแลส่วนตัว ด้วยการออกแบบที่ได้มาตรฐานและใช้งานง่าย SR060 จึงเป็นที่นิยมสำหรับการผลิตในปริมาณมากในอุตสาหกรรม B2B วัสดุ PE รับรองความปลอดภัยและความทนทานในการสัมผัสกับผลิตภัณฑ์หลากหลายชนิด เหมาะสำหรับโลชั่น เซรั่ม และผลิตภัณฑ์ของเหลวในบรรจุภัณฑ์แบบ flexible pouch รุ่น HL060D ขนาด 6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL060D (SR060) plastic spout cap with a 6mm inner diameter is a standardized PE spout widely used in cosmetic, beauty, and personal care liquid pouch p...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl060d-sr060-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl060d-sr060-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL060D-SR060.jpg', 'จุกพลาสติก HL060D SR060 ขนาด 6 มม. PE สำหรับซองบรรจุของเหลวและเครื่องสำอาง', 'Plastic Spout HL060D SR060 6mm PE for Liquid Pouch and Cosmetic Packaging', 1, 1),
  ('product:plastic-spout-hl048d-cx048-4-8mm', 'จุกพลาสติก HL048D (CX048) ขนาด 4.8 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL048D (CX048) 4.8mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL048D หรือ CX048 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 4.8 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวที่ต้องการการควบคุมปริมาณอย่างแม่นยำ ขนาด 4.8 มม. ให้ความสมดุลระหว่างการควบคุมปริมาณและอัตราการไหลที่เหมาะสม เหมาะสำหรับผลิตภัณฑ์ความงาม เจล ครีม และของเหลวที่มีความหนืดปานกลาง วัสดุ PE รับรองความปลอดภัยและทนทาน เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับบรรจุภัณฑ์แบบ flexible pouch รุ่น HL048D ขนาด 4.8 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL048D (CX048) plastic spout features a 4.8mm inner diameter made from PE material, providing precise flow control for cosmetic, beauty, and liquid pou...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl048d-cx048-4-8mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl048d-cx048-4-8mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL048DCX048.jpg', 'จุกพลาสติก HL048D CX048 ขนาด 4.8 มม. PE สำหรับบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL048D CX048 4.8mm PE for Cosmetic Liquid Packaging', 1, 1),
  ('product:plastic-spout-hl013-3mm', 'จุกพลาสติก HL013 ขนาด 3 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL013 3mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL013 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 3 มม. ออกแบบมาสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการจ่ายของเหลวในปริมาณน้อยและแม่นยำ เหมาะสำหรับผลิตภัณฑ์ที่มีความหนืดสูง เช่น เจลเข้มข้น เซรั่ม และผลิตภัณฑ์ที่ต้องการการควบคุมปริมาณอย่างแม่นยำ วัสดุ PE ให้ความทนทานและความปลอดภัยในการสัมผัสกับสารเคมีหลากหลายชนิด เหมาะสำหรับการผลิตในปริมาณมากสำหรับอุตสาหกรรม B2B บรรจุภัณฑ์แบบ flexible pouch และซองรีฟิล รุ่น HL013 ขนาด 3 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL013 plastic spout with a 3mm inner diameter is manufactured from PE material, providing controlled and precise liquid dispensing ideal for cosmetic a...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl013-3mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl013-3mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL013.jpg', 'จุกพลาสติก HL013 ขนาด 3 มม. PE สำหรับซองเครื่องสำอางและรีฟิล', 'Plastic Spout HL013 3mm PE for Cosmetic Pouch and Refill Packaging', 1, 1),
  ('product:plastic-spout-hl070dt-7mm', 'จุกพลาสติก HL070DT ขนาด 7 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL070DT 7mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL070DT ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 7 มม. รุ่น DT มีการออกแบบพิเศษที่รองรับการใช้งานในบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ความงาม และซองรีฟิลของเหลว ขนาด 7 มม. ให้อัตราการไหลที่ดีเหมาะสำหรับโลชั่น แชมพู ครีมนวด และผลิตภัณฑ์ของเหลวที่ใช้ในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE ให้ความทนทาน ความปลอดภัย และความเข้ากันได้กับสารเคมีหลากหลายชนิด เหมาะสำหรับผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการจุกสำหรับซองบรรจุภัณฑ์คุณภาพสูง รุ่น HL070DT ขนาด 7 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL070DT plastic spout features a 7mm inner diameter and is made from PE material, with a specialized DT design for cosmetic, beauty, and liquid pouch p...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl070dt-7mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl070dt-7mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL070DT.jpg', 'จุกพลาสติก HL070DT ขนาด 7 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์ของเหลว', 'Plastic Spout HL070DT 7mm PE for Refill Pouch and Liquid Packaging', 1, 1),
  ('product:plastic-spout-hl070-7mm', 'จุกพลาสติก HL070 ขนาด 7 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL070 7mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL070 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 7 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวที่ต้องการอัตราการไหลที่สม่ำเสมอ ขนาด 7 มม. รองรับผลิตภัณฑ์หลากหลายชนิดตั้งแต่โลชั่น ครีม ไปจนถึงแชมพูและผลิตภัณฑ์ทำความสะอาด วัสดุ PE ให้ความทนทานและความปลอดภัยในการสัมผัสกับสารเคมี เป็นตัวเลือกยอดนิยมสำหรับผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการจุกพลาสติกสำหรับ flexible pouch และซองรีฟิลคุณภาพสูง รุ่น HL070 ขนาด 7 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL070 plastic spout with a 7mm inner diameter is produced from PE material, offering versatile liquid dispensing for cosmetic, personal care, and liqui...', 'https://168innovative.co.th/categories/lipstick-packaging/plastic-spout-hl070-7mm', 'https://168innovative.co.th/en/categories/lipstick-packaging/plastic-spout-hl070-7mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL070.jpg', 'จุกพลาสติก HL070 ขนาด 7 มม. PE สำหรับซองบรรจุของเหลวและรีฟิล', 'Plastic Spout HL070 7mm PE for Liquid Pouch and Refill Packaging', 1, 1),
  ('product:plastic-spout-hl070j-7mm', 'จุกพลาสติก HL070J ขนาด 7 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL070J 7mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL070J ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 7 มม. รุ่น J มีการออกแบบที่แตกต่างออกไปเพื่อรองรับการใช้งานเฉพาะทางในบรรจุภัณฑ์เครื่องสำอางและซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์ความงาม โลชั่น เจล และของเหลวในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE รับรองความทนทานและความปลอดภัยในการใช้งาน เป็นตัวเลือกที่น่าเชื่อถือสำหรับผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการบรรจุภัณฑ์คุณภาพสูงในปริมาณมาก รุ่น HL070J ขนาด 7 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL070J plastic spout with a 7mm inner diameter is crafted from PE material with a J-variant design tailored for specific cosmetic and liquid pouch pack...', 'https://168innovative.co.th/categories/mascara-packaging/plastic-spout-hl070j-7mm', 'https://168innovative.co.th/en/categories/mascara-packaging/plastic-spout-hl070j-7mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL070J.jpg', 'จุกพลาสติก HL070J ขนาด 7 มม. PE สำหรับบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL070J 7mm PE for Cosmetic and Beauty Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl070dl-7mm', 'จุกพลาสติก HL070DL ขนาด 7 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL070DL 7mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL070DL ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 7 มม. รุ่น DL มีการออกแบบที่เน้นความสะดวกในการใช้งานและการปิดผนึกที่มีประสิทธิภาพสูง เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวในอุตสาหกรรมความงาม วัสดุ PE ให้ความทนทานและความเข้ากันได้กับสารเคมีหลากหลาย เหมาะสำหรับการผลิตในปริมาณมากในอุตสาหกรรม B2B ตอบโจทย์ผู้ผลิตที่ต้องการจุกพลาสติกคุณภาพสูงสำหรับ flexible pouch packaging รุ่น HL070DL ขนาด 7 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL070DL plastic spout features a 7mm inner diameter manufactured from PE material, with a DL design focused on ease of use and high-efficiency sealing...', 'https://168innovative.co.th/categories/lipstick-packaging/plastic-spout-hl070dl-7mm', 'https://168innovative.co.th/en/categories/lipstick-packaging/plastic-spout-hl070dl-7mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL070DL.jpg', 'จุกพลาสติก HL070DL ขนาด 7 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์ของเหลว', 'Plastic Spout HL070DL 7mm PE for Liquid Pouch and Refill Packaging', 1, 1),
  ('product:plastic-spout-hl070dlj-7mm', 'จุกพลาสติก HL070DLJ ขนาด 7 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL070DLJ 7mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL070DLJ ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 7 มม. รุ่น DLJ รวมคุณสมบัติของการออกแบบ DL และ J เพื่อตอบสนองความต้องการเฉพาะทางในบรรจุภัณฑ์เครื่องสำอางและซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์ความงาม โลชั่น เจล และของเหลวในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE รับรองความทนทานและความปลอดภัย เป็นตัวเลือกระดับพรีเมียมสำหรับผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการบรรจุภัณฑ์คุณภาพสูงสำหรับสินค้าที่มีมูลค่าสูง รุ่น HL070DLJ ขนาด 7 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL070DLJ plastic spout combines DL and J design elements in a 7mm inner diameter PE spout, offering a specialized solution for premium cosmetic and liq...', 'https://168innovative.co.th/categories/mascara-packaging/plastic-spout-hl070dlj-7mm', 'https://168innovative.co.th/en/categories/mascara-packaging/plastic-spout-hl070dlj-7mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL070DLJ.jpg', 'จุกพลาสติก HL070DLJ ขนาด 7 มม. PE สำหรับซองเครื่องสำอางระดับพรีเมียม', 'Plastic Spout HL070DLJ 7mm PE for Premium Cosmetic Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl082d-8-2mm', 'จุกพลาสติก HL082D ขนาด 8.2 มม. | จุกซอง 8mm | OEM', 'Plastic Spout HL082D 8.2mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL082D ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.2 มม. เป็นมาตรฐานยอดนิยมในอุตสาหกรรมบรรจุภัณฑ์สำหรับซองรีฟิล อาหาร เครื่องดื่ม และผลิตภัณฑ์ของเหลวในบรรจุภัณฑ์แบบ flexible pouch ขนาด 8.2 มม. รองรับการไหลของเหลวหนืดและของเหลวอาหารได้ดีเยี่ยม เช่น น้ำผลไม้ ซอส น้ำเกรวี่ และผลิตภัณฑ์อาหารสำหรับทารก วัสดุ PE ผ่านมาตรฐานความปลอดภัยด้านอาหารและเป็นที่นิยมในอุตสาหกรรม B2B ทั่วโลก รุ่น HL082D ขนาด 8.2 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL082D plastic spout with an 8.2mm inner diameter is a widely adopted PE spout standard in flexible pouch packaging for food, beverage, refill, and liq...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl082d-8-2mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl082d-8-2mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL082D.jpg', 'จุกพลาสติก HL082D ขนาด 8.2 มม. PE สำหรับซองอาหารและซองรีฟิล', 'Plastic Spout HL082D 8.2mm PE for Food Pouch and Refill Packaging', 1, 1),
  ('product:plastic-spout-hl086p-8-6mm', 'จุกพลาสติก HL086P ขนาด 8.6 มม. | จุกซอง 8mm | OEM', 'Plastic Spout HL086P 8.6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL086P ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.6 มม. เป็นขนาดมาตรฐานที่นิยมใช้มากที่สุดในอุตสาหกรรมบรรจุภัณฑ์สำหรับอาหาร เครื่องดื่ม และซองรีฟิลของเหลว ขนาด 8.6 มม. รองรับผลิตภัณฑ์หลากหลายชนิดตั้งแต่น้ำผลไม้ น้ำซุป ซอสปรุงรส ไปจนถึงผลิตภัณฑ์เครื่องสำอางและผลิตภัณฑ์ดูแลบ้าน วัสดุ PE ผ่านมาตรฐานความปลอดภัยระดับสากลและเป็นที่ยอมรับในอุตสาหกรรม B2B ทั่วโลก เหมาะสำหรับการผลิตในปริมาณมากบนสายการผลิตอัตโนมัติ รุ่น HL086P ขนาด 8.6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL086P plastic spout at 8.6mm inner diameter is one of the most widely used standard PE spout sizes in the flexible pouch packaging industry. It serves...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl086p-8-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl086p-8-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL086P.jpg', 'จุกพลาสติก HL086P ขนาด 8.6 มม. PE สำหรับซองอาหารและเครื่องดื่ม', 'Plastic Spout HL086P 8.6mm PE for Food and Beverage Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl086h-8-6mm', 'จุกพลาสติก HL086H ขนาด 8.6 มม. | จุกซอง 8mm | OEM', 'Plastic Spout HL086H 8.6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL086H ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.6 มม. รุ่น H มีการออกแบบพิเศษที่เพิ่มความแข็งแรงและการปิดผนึกที่เหนือกว่า เหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลวที่ต้องการการปิดผนึกที่มั่นคงและปลอดภัย วัสดุ PE ผ่านมาตรฐานความปลอดภัยด้านอาหารและเคมีภัณฑ์ รองรับการใช้งานในอุตสาหกรรม B2B ทั้งในด้านอาหาร เครื่องสำอาง และผลิตภัณฑ์ดูแลบ้าน เป็นตัวเลือกที่น่าเชื่อถือสำหรับผู้ผลิตที่ต้องการคุณภาพสูงในปริมาณมาก รุ่น HL086H ขนาด 8.6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL086H plastic spout with an 8.6mm inner diameter is made from PE material with an H-design offering enhanced structural strength and superior sealing...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl086h-8-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl086h-8-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL086H.jpg', 'จุกพลาสติก HL086H ขนาด 8.6 มม. PE สำหรับซองอาหารและของเหลว', 'Plastic Spout HL086H 8.6mm PE for Food and Liquid Pouch Packaging', 1, 1),
  ('product:plastic-spout-rd124-8-6mm', 'จุกพลาสติก RD124 ขนาด 8.6 มม. PE PP | จุกซอง 8mm | OEM', 'Plastic Spout RD124 8.6mm PE PP | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก RD124 ผลิตจากวัสดุ PE และ PP คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.6 มม. การผสมผสานระหว่างวัสดุ PE และ PP ทำให้ได้ทั้งความยืดหยุ่นจาก PE และความแข็งแรงจาก PP เหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลวที่ต้องการจุกที่มีคุณสมบัติพิเศษ รองรับการผลิตในปริมาณมากในอุตสาหกรรม B2B ทั้งด้านอาหาร เครื่องสำอาง และผลิตภัณฑ์ดูแลบ้าน วัสดุทั้งสองชนิดผ่านมาตรฐานความปลอดภัยระดับสากล รุ่น RD124 ขนาด 8.6 มม. วัสดุ PE, PP พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The RD124 plastic spout with an 8.6mm inner diameter is manufactured from a combination of PE and PP materials, offering the flexibility of PE with the rig...', 'https://168innovative.co.th/categories/spout/plastic-spout-rd124-8-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-rd124-8-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/RD124.jpg', 'จุกพลาสติก RD124 ขนาด 8.6 มม. PE PP สำหรับซองอาหารและรีฟิล', 'Plastic Spout RD124 8.6mm PE PP for Food Pouch and Refill Packaging', 1, 1),
  ('product:plastic-spout-hl086s-8-6mm', 'จุกพลาสติก HL086S ขนาด 8.6 มม. PE PP | จุกซอง 8mm | OEM', 'Plastic Spout HL086S 8.6mm PE PP | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL086S ผลิตจากวัสดุ PE และ PP คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.6 มม. รุ่น S ถูกออกแบบมาเพื่อการใช้งานในบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลวที่ต้องการวัสดุที่แข็งแรงและยืดหยุ่น การใช้วัสดุ PE และ PP ร่วมกันช่วยเพิ่มความทนทานและความปลอดภัยในการสัมผัสกับสารอาหารและเคมีภัณฑ์ เหมาะสำหรับผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการบรรจุภัณฑ์คุณภาพสูงและผลิตได้ในปริมาณมาก รุ่น HL086S ขนาด 8.6 มม. วัสดุ PE, PP พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL086S plastic spout with an 8.6mm inner diameter combines PE and PP materials in an S-design, providing a balance of flexibility and rigidity for food...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl086s-8-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl086s-8-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL086S.jpg', 'จุกพลาสติก HL086S ขนาด 8.6 มม. PE PP สำหรับซองบรรจุของเหลวและอาหาร', 'Plastic Spout HL086S 8.6mm PE PP for Food and Liquid Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl086d-8-6mm', 'จุกพลาสติก HL086D ขนาด 8.6 มม. | จุกซอง 8mm | OEM', 'Plastic Spout HL086D 8.6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL086D ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.6 มม. รุ่น D มีโครงสร้างที่แข็งแรงและเหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม เครื่องสำอาง และซองรีฟิลของเหลวในอุตสาหกรรม B2B ขนาด 8.6 มม. เป็นมาตรฐานที่ใช้กันอย่างแพร่หลายในอุตสาหกรรมบรรจุภัณฑ์ทั่วโลก วัสดุ PE ผ่านมาตรฐานความปลอดภัยด้านอาหารและเคมีภัณฑ์ รองรับการผลิตในปริมาณมากบนสายการผลิตอัตโนมัติ รุ่น HL086D ขนาด 8.6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL086D plastic spout with an 8.6mm inner diameter is a robust PE spout designed for food, beverage, cosmetic, and refill liquid pouch packaging. The D-...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl086d-8-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl086d-8-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL086D.jpg', 'จุกพลาสติก HL086D ขนาด 8.6 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์ของเหลว', 'Plastic Spout HL086D 8.6mm PE for Refill Pouch and Liquid Packaging', 1, 1),
  ('product:plastic-spout-hl086m-8-6mm', 'จุกพลาสติก HL086M ขนาด 8.6 มม. | จุกซอง 8mm | OEM', 'Plastic Spout HL086M 8.6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL086M ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.6 มม. รุ่น M มีการออกแบบที่ตอบสนองความต้องการเฉพาะทางในบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์อาหารสำหรับทารก น้ำผลไม้ ซอส และผลิตภัณฑ์ของเหลวในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE ปลอดภัยสำหรับการสัมผัสกับอาหารและเครื่องดื่ม รองรับการผลิตในปริมาณมากในอุตสาหกรรม B2B รุ่น HL086M ขนาด 8.6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL086M plastic spout features an 8.6mm inner diameter in PE material with an M-design tailored for food, beverage, and liquid pouch packaging. This spo...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl086m-8-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl086m-8-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL086M.jpg', 'จุกพลาสติก HL086M ขนาด 8.6 มม. PE สำหรับซองอาหารและเครื่องดื่ม', 'Plastic Spout HL086M 8.6mm PE for Food and Beverage Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl086dl-8-6mm-ldpe', 'จุกพลาสติก HL086DL ขนาด 8.6 มม. LDPE | จุกซอง 8mm | OEM', 'Plastic Spout HL086DL 8.6mm LDPE | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL086DL ผลิตจาก LDPE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 8.6 มม. วัสดุ LDPE ให้ความยืดหยุ่นสูงกว่า PE ทั่วไป เหมาะสำหรับบรรจุภัณฑ์ที่ต้องการการบีบและการจ่ายผลิตภัณฑ์ที่นุ่มนวล เหมาะสำหรับอาหาร เครื่องดื่ม เครื่องสำอาง และซองรีฟิลของเหลว LDPE มีความเข้ากันได้กับสารอาหารและเคมีภัณฑ์หลากหลายชนิด เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับบรรจุภัณฑ์ flexible pouch ที่ต้องการความยืดหยุ่นสูง รุ่น HL086DL ขนาด 8.6 มม. วัสดุ LDPE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL086DL plastic spout with an 8.6mm inner diameter is manufactured from LDPE material, delivering superior flexibility for soft-squeeze dispensing appl...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl086dl-8-6mm-ldpe', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl086dl-8-6mm-ldpe', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL086DL.jpg', 'จุกพลาสติก HL086DL ขนาด 8.6 มม. LDPE สำหรับซองบรรจุของเหลวที่ต้องการความยืดหยุ่น', 'Plastic Spout HL086DL 8.6mm LDPE for Flexible Liquid Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl096-9-6mm', 'จุกพลาสติก HL096 ขนาด 9.6 มม. | จุกซอง 9.6mm | OEM', 'Plastic Spout HL096 9.6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL096 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 9.6 มม. ขนาด 9.6 มม. เหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลวที่ต้องการอัตราการไหลที่สูงขึ้น เหมาะสำหรับน้ำผลไม้ ซุป ซอส และผลิตภัณฑ์อาหารของเหลวในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE ผ่านมาตรฐานความปลอดภัยด้านอาหารและมีความทนทานสูง รองรับการผลิตในปริมาณมากในอุตสาหกรรม B2B สำหรับบรรจุภัณฑ์ที่ต้องการมาตรฐานสูง รุ่น HL096 ขนาด 9.6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL096 plastic spout features a 9.6mm inner diameter made from PE material, providing higher flow capacity for food, beverage, and liquid refill pouch p...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl096-9-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl096-9-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL096.jpg', 'จุกพลาสติก HL096 ขนาด 9.6 มม. PE สำหรับซองอาหารและเครื่องดื่ม', 'Plastic Spout HL096 9.6mm PE for Food and Beverage Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl096d-9-6mm', 'จุกพลาสติก HL096D ขนาด 9.6 มม. | จุกซอง 9.6mm | OEM', 'Plastic Spout HL096D 9.6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL096D ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 9.6 มม. รุ่น D มีโครงสร้างที่แข็งแรงและการปิดผนึกที่ดีเยี่ยม เหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลวในอุตสาหกรรม B2B ขนาด 9.6 มม. รองรับการไหลของของเหลวที่มีความหนืดปานกลาง วัสดุ PE ปลอดภัยสำหรับการสัมผัสกับอาหารและเคมีภัณฑ์ เป็นตัวเลือกที่น่าเชื่อถือสำหรับผู้ผลิตที่ต้องการบรรจุภัณฑ์มาตรฐานสูง รุ่น HL096D ขนาด 9.6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL096D plastic spout with a 9.6mm inner diameter is produced from PE material in a D-series robust construction, offering excellent sealing and flow pe...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl096d-9-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl096d-9-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL096D.jpg', 'จุกพลาสติก HL096D ขนาด 9.6 มม. PE สำหรับซองของเหลวและอาหาร', 'Plastic Spout HL096D 9.6mm PE for Liquid Pouch and Food Packaging', 1, 1),
  ('product:plastic-spout-hl096f-9-6mm', 'จุกพลาสติก HL096F ขนาด 9.6 มม. | จุกซอง 9.6mm | OEM', 'Plastic Spout HL096F 9.6mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL096F ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 9.6 มม. รุ่น F มีการออกแบบพิเศษที่รองรับการใช้งานในบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลว เหมาะสำหรับผู้ผลิตที่ต้องการจุกสำหรับ flexible pouch ที่มีประสิทธิภาพสูงในการปิดผนึกและการจ่ายผลิตภัณฑ์ วัสดุ PE ปลอดภัยสำหรับการสัมผัสกับอาหารและมีความทนทานสูง เหมาะสำหรับอุตสาหกรรม B2B ที่ต้องการคุณภาพและความน่าเชื่อถือในการผลิตปริมาณมาก รุ่น HL096F ขนาด 9.6 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL096F plastic spout at 9.6mm inner diameter is a PE-material spout with an F-series design for enhanced food, beverage, and liquid pouch packaging per...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl096f-9-6mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl096f-9-6mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL096F.jpg', 'จุกพลาสติก HL096F ขนาด 9.6 มม. PE สำหรับซองอาหารและรีฟิล', 'Plastic Spout HL096F 9.6mm PE for Food Pouch and Refill Packaging', 1, 1),
  ('product:plastic-spout-hl100s-10mm', 'จุกพลาสติก HL100S ขนาด 10 มม. PE PP | จุกซอง 10mm | OEM', 'Plastic Spout HL100S 10mm PE PP | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL100S ผลิตจากวัสดุ PE และ PP คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 10 มม. การใช้วัสดุ PE และ PP ร่วมกันทำให้ได้ทั้งความยืดหยุ่นและความแข็งแรงที่เหมาะสม เหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม เครื่องสำอาง และซองรีฟิลของเหลวในอุตสาหกรรม B2B ขนาด 10 มม. รองรับการไหลของของเหลวที่ดีขึ้น เหมาะสำหรับผลิตภัณฑ์ที่มีความหนืดปานกลางถึงสูง วัสดุทั้งสองชนิดผ่านมาตรฐานความปลอดภัยระดับสากล รุ่น HL100S ขนาด 10 มม. วัสดุ PE, PP พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL100S plastic spout with a 10mm inner diameter combines PE and PP materials, offering an ideal balance of flexibility and structural strength for food...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl100s-10mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl100s-10mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL100S.jpg', 'จุกพลาสติก HL100S ขนาด 10 มม. PE PP สำหรับซองอาหารและรีฟิล', 'Plastic Spout HL100S 10mm PE PP for Food Pouch and Refill Packaging', 1, 1),
  ('product:plastic-spout-hl100sl-10mm', 'จุกพลาสติก HL100SL ขนาด 10 มม. | จุกซอง 10mm | OEM', 'Plastic Spout HL100SL 10mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL100SL ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 10 มม. รุ่น SL มีการออกแบบที่เน้นความยาวของจุกเพื่อรองรับบรรจุภัณฑ์เฉพาะทาง เหมาะสำหรับอาหาร เครื่องดื่ม และซองรีฟิลของเหลวในอุตสาหกรรม B2B วัสดุ PE ปลอดภัยสำหรับการสัมผัสกับอาหารและมีความทนทานต่อสารเคมี เหมาะสำหรับผู้ผลิตที่ต้องการบรรจุภัณฑ์มาตรฐานสูงในปริมาณมากบนสายการผลิตอัตโนมัติ รุ่น HL100SL ขนาด 10 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL100SL plastic spout with a 10mm inner diameter is manufactured from PE material in an SL design featuring an extended spout length for specialized pa...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl100sl-10mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl100sl-10mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL100SL.jpg', 'จุกพลาสติก HL100SL ขนาด 10 มม. PE สำหรับซองบรรจุของเหลวและอาหาร', 'Plastic Spout HL100SL 10mm PE for Liquid Pouch and Food Packaging', 1, 1),
  ('product:plastic-spout-hl100sm-10mm', 'จุกพลาสติก HL100SM ขนาด 10 มม. | จุกซอง 10mm | OEM', 'Plastic Spout HL100SM 10mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL100SM ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 10 มม. รุ่น SM มีการออกแบบที่รวมคุณสมบัติของขนาดและการปิดผนึกที่เหมาะสมสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์ของเหลวในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE ปลอดภัยและทนทาน เป็นตัวเลือกที่น่าเชื่อถือสำหรับอุตสาหกรรม B2B ที่ต้องการคุณภาพและความสม่ำเสมอในการผลิตปริมาณมาก รุ่น HL100SM ขนาด 10 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL100SM plastic spout features a 10mm inner diameter made from PE material, combining practical sizing and sealing characteristics for food, beverage,...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl100sm-10mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl100sm-10mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL100SM.jpg', 'จุกพลาสติก HL100SM ขนาด 10 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์ของเหลว', 'Plastic Spout HL100SM 10mm PE for Refill Pouch and Liquid Packaging', 1, 1),
  ('product:plastic-spout-hl100w-10mm', 'จุกพลาสติก HL100W ขนาด 10 มม. | จุกซอง 10mm | OEM', 'Plastic Spout HL100W 10mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL100W ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 10 มม. รุ่น W มีการออกแบบปากกว้างที่รองรับการไหลของเหลวได้ดีเยี่ยม เหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม และซองรีฟิลของเหลวที่ต้องการอัตราการไหลที่สูง ใช้กันอย่างแพร่หลายในอุตสาหกรรม B2B สำหรับน้ำผลไม้ ซอส ผลิตภัณฑ์นม และของเหลวอาหารในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE ปลอดภัยและทนทาน รุ่น HL100W ขนาด 10 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL100W plastic spout with a 10mm inner diameter is manufactured from PE material in a W-design offering wide-opening performance for high-flow liquid p...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl100w-10mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl100w-10mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL100W.jpg', 'จุกพลาสติก HL100W ขนาด 10 มม. PE สำหรับซองอาหารและเครื่องดื่ม', 'Plastic Spout HL100W 10mm PE for Food and Beverage Pouch Packaging', 1, 1),
  ('product:plastic-spout-hl130w-13mm', 'จุกพลาสติก HL130W ขนาด 13 มม. | จุกซองขนาดกลาง | OEM', 'Plastic Spout HL130W 13mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL130W ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 13 มม. จัดอยู่ในกลุ่มจุกขนาดกลางที่เหมาะสำหรับบรรจุภัณฑ์อาหาร เครื่องดื่ม ผลิตภัณฑ์ดูแลบ้าน และซองรีฟิลของเหลวในอุตสาหกรรม B2B ขนาด 13 มม. รองรับการไหลของของเหลวที่มีความหนืดสูงขึ้น เช่น ซอส แชมพู น้ำยาทำความสะอาด และผลิตภัณฑ์ดูแลบ้านในบรรจุภัณฑ์แบบ flexible pouch รุ่น W มีการออกแบบปากกว้างที่ช่วยเพิ่มประสิทธิภาพในการบรรจุและการจ่ายผลิตภัณฑ์ รุ่น HL130W ขนาด 13 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL130W plastic spout with a 13mm inner diameter is a medium-size PE spout designed for food, beverage, household, and liquid refill pouch packaging. Th...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl130w-13mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl130w-13mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL130W.jpg', 'จุกพลาสติก HL130W ขนาด 13 มม. PE สำหรับซองรีฟิลและผลิตภัณฑ์ดูแลบ้าน', 'Plastic Spout HL130W 13mm PE for Refill Pouch and Household Liquid Packaging', 1, 1),
  ('product:plastic-spout-hl130d-13mm', 'จุกพลาสติก HL130D ขนาด 13 มม. | จุกซองขนาดกลาง | OEM', 'Plastic Spout HL130D 13mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL130D ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 13 มม. รุ่น D มีโครงสร้างที่แข็งแรงและการปิดผนึกที่เชื่อถือได้ เหมาะสำหรับบรรจุภัณฑ์อาหาร ผลิตภัณฑ์ดูแลบ้าน และซองรีฟิลของเหลวในอุตสาหกรรม B2B วัสดุ PE ปลอดภัยสำหรับการสัมผัสกับอาหารและสารเคมี รองรับการผลิตในปริมาณมากบนสายการผลิตอัตโนมัติ เหมาะสำหรับผลิตภัณฑ์ที่มีความหนืดสูงในบรรจุภัณฑ์แบบ flexible pouch รุ่น HL130D ขนาด 13 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL130D plastic spout at 13mm inner diameter is a robust PE medium-size spout engineered for food, household, and liquid refill pouch packaging. The D-s...', 'https://168innovative.co.th/categories/spout/plastic-spout-hl130d-13mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl130d-13mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL130D.jpg', 'จุกพลาสติก HL130D ขนาด 13 มม. PE สำหรับซองของเหลวและผลิตภัณฑ์ดูแลบ้าน', 'Plastic Spout HL130D 13mm PE for Liquid Pouch and Household Product Packaging', 1, 1),
  ('product:plastic-spout-hl130d-a-13mm', 'จุกซองครีม HL130D-A ขนาด 13 มม. | จุกซองขนาดกลาง | OEM', 'Plastic Spout HL130D-A 14mm | Cosmetic Packaging OEM / ODM', 'จุกซองครีม จุกพลาสติก HL130D-A ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 13 มม. รุ่น J มีการออกแบบพิเศษที่รองรับการใช้งานในบรรจุภัณฑ์อาหาร   และซองรีฟิลของเหลวที่ต้องการการไหลที่ดี ขนาด 13 มม. เหมาะสำหรับผลิตภัณฑ์ที่มีความหนืดปานกลางถึงสูงในบรรจุภัณฑ์แบบ flexible pouch วัสดุ PE ให้ความทนทานและความปลอดภัยในการสัมผัสกับอาหารและสารเคมี เป็นตัวเลือกที่น่าเชื่อถือสำหรับผู้ผลิตในอุตสาหกรรม B2B รุ่น HL130D-A ขนาด 13 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL130D-A plastic spout with a 13mm inner diameter is manufactured from PE material in a J-variant design for food, household, and liquid refill pouch package.', 'https://168innovative.co.th/categories/spout/plastic-spout-hl140j-14mm', 'https://168innovative.co.th/en/categories/spout/plastic-spout-hl140j-14mm', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL140J.jpg', 'จุกติดซองครีม HL130D-A ขนาด 13 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์ของเหลว', 'Plastic Spout HL130D-A 13mm PE for Refill Pouch and Liquid Packaging', 1, 1),
