INSERT INTO `home_hero_slides` (`id`, `theme`, `badge_variant`, `badge_text_th`, `badge_text_en`, `title_th`, `title_en`, `description_th`, `description_en`, `image_url`, `image_alt_th`, `image_alt_en`, `cta_primary_label_th`, `cta_primary_label_en`, `cta_primary_href`, `cta_secondary_label_th`, `cta_secondary_label_en`, `cta_secondary_href`, `highlight_value`, `highlight_label_th`, `highlight_label_en`, `visual_title_th`, `visual_title_en`, `visual_subtitle_th`, `visual_subtitle_en`, `sort_order`, `is_published`) VALUES
  (48, 'rose', 'featured', 'ผู้เชี่ยวชาญด้านบรรจุภัณฑ์และผลิตภัณฑ์พลาสติก', 'Experts in Plastic Packaging & Distribution', '168 Innovative ', '168 Innovative', 'ผู้นำเข้าและจัดจำหน่ายบรรจุภัณฑ์และผลิตภัณฑ์พลาสติกคุณภาพสูง\nรองรับธุรกิจเครื่องสำอาง อาหาร และสินค้าอุปโภคบริโภคทั่วประเทศ\n\n✓ คัดเลือกผู้ผลิตต่างประเทศที่ได้มาตรฐาน\n✓ ตรวจสอบเอกสารและสเปกสินค้าก่อนนำเข้า\n✓ ให้คำปรึกษาและบริการอย่างมืออาชีพ', 'We import and distribute high-quality plastic packaging and products,\nserving cosmetics, food, and consumer goods industries nationwide.\n\n✓ Carefully selected international manufacturers\n✓ Verified specifications and certifications\n✓ Professional consultation and support', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/สีชมพู-สีขาว-สง่างาม-คลินิกความงาม-ธุรกิจ-ภาพหน้าปก-Facebook-1-1.webp', '168 Innovative ', '168 Innovative', 'ดูสินค้า', 'View Products', '/categories', 'ติดต่อเรา', 'Contact Us', '/contact', NULL, NULL, NULL, '168 Innovative ', '168 Innovative', 'ผู้เชี่ยวชาญด้านบรรจุภัณฑ์และผลิตภัณฑ์พลาสติก', 'Experts in Plastic Packaging & Distribution', 1, 1),
  (49, 'sky', 'featured', 'ตอบโจทย์ทุกความต้องการทางธุรกิจ', 'Supporting Every Business Requirement', 'จำหน่ายบรรจุภัณฑ์ครบวงจร', 'Comprehensive Packaging Solutions', 'จัดจำหน่ายบรรจุภัณฑ์พลาสติกหลากหลายรูปแบบ\nพร้อมรองรับการสั่งนำเข้าเพิ่มเติมตามความต้องการของลูกค้า\n\n✓ สินค้าหลากหลายประเภทและขนาด\n✓ รองรับคำสั่งซื้อจำนวนมาก\n✓ จัดส่งทั่วประเทศ', 'We offer a wide range of plastic packaging products\nand provide flexible import services based on customer requirements.\n\n✓ Various designs and sizes available\n✓ Bulk order support\n✓ Nationwide delivery', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/Lipstick-spout.webp', 'จำหน่ายบรรจุภัณฑ์ครบวงจร', 'Comprehensive Packaging Solutions', 'ดูสินค้า', 'View Products', '/categories', 'ติดต่อเรา', 'Contact Us →', '/contact', NULL, NULL, NULL, 'จำหน่ายบรรจุภัณฑ์ครบวงจร', 'Comprehensive Packaging Solutions', 'ตอบโจทย์ทุกความต้องการทางธุรกิจ', 'Supporting Every Business Requirement', 2, 1);
INSERT INTO `why_items` (`id`, `page_key`, `section_key`, `icon_name`, `image_url`, `image_alt_th`, `image_alt_en`, `title_th`, `title_en`, `description_th`, `description_en`, `sort_order`, `is_published`) VALUES
  (86, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/direct_import.png', 'ราคาโรงงาน', 'Factory Price', 'ราคาโรงงาน', 'Factory Price', 'นำเข้าโดยตรง ไม่ผ่านคนกลาง ทำให้ได้ราคาที่ดีที่สุด', 'Direct import without middlemen for the best competitive prices.', 1, 1),
  (168, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/quality_standard.png', 'คุณภาพพรีเมียม', 'Premium Quality', 'คุณภาพพรีเมียม', 'Premium Quality', 'คัดสรรวัสดุ Food Grade และ Cosmetic Grade ที่ปลอดภัย', 'Selection of safe Food Grade and Cosmetic Grade materials.', 2, 1),
  (169, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/oem_support.png', 'รองรับ OEM', 'OEM Support', 'รองรับ OEM', 'OEM Support', 'ทีมงานเข้าใจความต้องการของแบรนด์ OEM อย่างแท้จริง', 'Our team understands the real needs of OEM brands.', 3, 1),
  (170, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/reliable_supply.png', 'ซัพพลายเชนมั่นคง', 'Reliable Supply', 'ซัพพลายเชนมั่นคง', 'Reliable Supply', 'ควบคุมคุณภาพและการจัดส่งอย่างเป็นระบบ เพื่อความต่อเนื่องในการผลิต', 'Systematic quality control and logistics for consistent production.', 4, 1);
INSERT INTO `about_sections` (`id`, `section_key`, `eyebrow_th`, `eyebrow_en`, `title_th`, `title_en`, `description_th`, `description_en`, `image_primary_url`, `image_primary_alt_th`, `image_primary_alt_en`, `image_secondary_url`, `image_secondary_alt_th`, `image_secondary_alt_en`, `sort_order`, `is_published`) VALUES
  (1, 'hero', NULL, NULL, 'นำเข้าและจัดจำหน่ายบรรจุภัณฑ์เครื่องสำอาง และผลิตภัณฑ์พลาสติกสำหรับแบรนด์ OEM', 'Importer and Distributor of Cosmetic Packaging for OEM Brands and Manufacturers', '168 Innovative Co., Ltd. ให้บริการจัดหาและนำเข้าบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์พลาสติกที่หลากหลาย เพื่อตอบโจทย์ธุรกิจ OEM และผู้ผลิตสินค้าในอุตสาหกรรมความงาม โดยสินค้าของเราครอบคลุมหมวดหมู่บรรจุภัณฑ์ที่สำคัญ เช่น จุกซองและอุปกรณ์บรรจุภัณฑ์ ตลับแป้งและบรรจุภัณฑ์เครื่องสำอาง ถุงสูญญากาศและถุงบรรจุภัณฑ์ ที่จับพลาสติกและชิ้นส่วนประกอบ บรรจุภัณฑ์มาสคาร่า ขวดปั๊มและบรรจุภัณฑ์พลาสติก แท่งคอสเมติกและภาชนะบรรจุ รวมถึงโซ่ลูกปัดและอุปกรณ์เสริมสำหรับงานบรรจุภัณฑ์ ทีมงานของเรามุ่งเน้นการคัดเลือกสินค้าที่มีคุณภาพจากผู้ผลิตที่เชื่อถือได้ พร้อมทั้งบริหารจัดการคลังสินค้าและระบบจัดส่งอย่างมีประสิทธิภาพ เพื่อให้ลูกค้าสามารถเข้าถึงบรรจุภัณฑ์ที่เหมาะสมกับผลิตภัณฑ์และการผลิตได้อย่างต่อเนื่อง', '168 Innovative Co., Ltd. provides sourcing and distribution services for a wide range of cosmetic packaging and plastic components designed to support OEM brands and manufacturers in the beauty industry. Our product categories include spout caps and packaging components, compact powder cases and cosmetic containers, vacuum bags and packaging pouches, plastic handles and components, mascara packaging, pump bottles and plastic containers, cosmetic stick containers, as well as ball chains and packaging accessories. We focus on selecting reliable manufacturing partners and maintaining efficient inventory management to ensure a consistent and dependable supply of packaging solutions for our customers.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/factory.png', 'กระบวนการคัดเลือกและตรวจสอบคุณภาพบรรจุภัณฑ์', 'Warehouse and packaging inventory management system', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/warehouse.jpg', 'คลังสินค้าและระบบจัดการสต็อกบรรจุภัณฑ์', 'คลังสินค้าและระบบจัดการสต็อกบรรจุภัณฑ์', 1, 1),
  (2, 'who-we-are', NULL, NULL, 'พวกเราคือใคร', 'Who We Are', 'เรามีความเชี่ยวชาญในการคัดสรรและนำเข้าชิ้นส่วนบรรจุภัณฑ์พลาสติกคุณภาพสูง พร้อมบริหารจัดการซัพพลายเชนและสต็อกสินค้า เพื่อรองรับความต้องการของแบรนด์ OEM อย่างต่อเนื่องและมั่นคง', 'We specialize in sourcing and importing high-quality plastic packaging components, managing supply chains and inventory to consistently support OEM brands with stability and reliability.', NULL, NULL, NULL, NULL, NULL, NULL, 2, 1);
INSERT INTO `categories` (`id`, `slug`, `name_th`, `name_en`, `description_th`, `description_en`, `intro_html_th`, `intro_html_en`, `seo_title_th`, `seo_title_en`, `seo_description_th`, `seo_description_en`, `image_url`, `image_alt_th`, `image_alt_en`, `sort_order`, `is_published`) VALUES
  (5, 'spout', 'จุกซอง', 'Spout Caps', 'จุกซอง จุกติดซอง ซองติดจุก และฝาจุกพลาสติกสำหรับซองบรรจุครีม เจล \nน้ำ และของเหลวทุกชนิด ผลิตจาก HDPE/PE คุณภาพสูง \nรองรับเครื่องบรรจุหลากหลายประเภท รับผลิต OEM/ODM', 'Plastic spout caps for cream, gel, and liquid flexible pouches. \nMade from high-quality HDPE and PE materials. Compatible with \nvarious filling machines. OEM/ODM manufacturing available.', '&lt;h2&gt;จุกซองพลาสติก สำหรับบรรจุภัณฑ์แบบซองครบวงจร&lt;/h2&gt;\n&lt;p&gt;168 Innovative ผู้ผลิตและจำหน่าย &lt;strong&gt;จุกซอง\nจุกติดซอง&lt;/strong&gt; และฝาจุกพลาสติกคุณภาพสูง สำหรับ\nอุตสาหกรรมเครื่องสำอาง อาหาร และของเหลวทุกชนิด\nผลิตจากวัสดุ HDPE และ PE ปลอดภัย ปลอดสาร BPA\nได้มาตรฐานอุตสาหกรรม&lt;/p&gt;\n\n&lt;h3&gt;เหมาะสำหรับการใช้งานใดบ้าง?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ซองเครื่องสำอางและผลิตภัณฑ์ดูแลผิว (ครีม เจล เซรั่ม)&lt;/li&gt;\n&lt;li&gt;ซองบรรจุอาหารและเครื่องดื่ม (ซอส น้ำผลไม้ นม)&lt;/li&gt;\n&lt;li&gt;ซองรีฟิลผลิตภัณฑ์ทำความสะอาดในบ้าน&lt;/li&gt;\n&lt;li&gt;บรรจุภัณฑ์ household chemical และสารเคมีเกษตร&lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;h3&gt;ทำไมต้องเลือก 168 Innovative?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;วัสดุ HDPE/PE คุณภาพสูง food-safe ปลอดสาร BPA&lt;/li&gt;\n&lt;li&gt;รองรับเครื่องบรรจุหลากหลายประเภทและขนาด&lt;/li&gt;\n&lt;li&gt;รับผลิต OEM/ODM ตามแบบ custom mold&lt;/li&gt;\n&lt;li&gt;รองรับ private label และพิมพ์โลโก้ได้&lt;/li&gt;\n&lt;li&gt;สั่งผลิตจำนวนมาก ราคาส่ง ส่งทั่วไทยและส่งออก&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Plastic Spout Caps for Flexible Pouch Packaging&lt;/h2&gt;\n&lt;p&gt;168 Innovative manufactures and supplies premium\n&lt;strong&gt;plastic spout caps&lt;/strong&gt; for cosmetic, food,\nand liquid flexible packaging industries. All products are\nmade from high-quality HDPE and PE — BPA-free and\nfood-safe certified.&lt;/p&gt;\n\n&lt;h3&gt;Applications&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Cosmetic and skincare pouches (cream, gel, serum)&lt;/li&gt;\n&lt;li&gt;Food and beverage flexible packaging (sauce, juice, dairy)&lt;/li&gt;\n&lt;li&gt;Household cleaning product refill pouches&lt;/li&gt;\n&lt;li&gt;Agricultural and industrial liquid packaging&lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;h3&gt;Why Choose 168 Innovative?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;High-quality HDPE/PE — BPA-free and food-safe&lt;/li&gt;\n&lt;li&gt;Compatible with various filling machines and pouch sizes&lt;/li&gt;\n&lt;li&gt;OEM/ODM custom mold production available&lt;/li&gt;\n&lt;li&gt;Private label and logo printing supported&lt;/li&gt;\n&lt;li&gt;Bulk orders welcome — serving Thailand and export markets&lt;/li&gt;\n&lt;/ul&gt;', 'จุกซอง จุกติดซอง พลาสติก OEM | 168 Innovative', 'Plastic Spout Caps OEM Manufacturer Thailand | 168 Innovative', 'จุกซองพลาสติก จุกติดซอง วัสดุ HDPE คุณภาพสูง \nเหมาะสำหรับเครื่องสำอาง อาหาร และของเหลว \nรับผลิต OEM/ODM จำนวนมาก ส่งทั่วไทยและส่งออก \nติดต่อขอใบเสนอราคาได้เลย', 'High-quality HDPE plastic spout caps for cosmetic, food, and \nliquid flexible pouch packaging. OEM/ODM manufacturing. \nBulk orders available. Request a quote today.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/spout.webp', 'จุกซอง', 'Spout Caps', 5, 1),
  (6, 'dispensing-press-cap', 'ฝาพลาสติก ฝากด', 'Dispensing Press Cap', 'ฝาพลาสติกแบบกด ฝากด สำหรับขวดครีม โลชั่น เจล และของเหลว ใช้งานง่ายด้วยมือเดียว ควบคุมปริมาณได้แม่นยำ รับผลิต OEM/ODM', 'Dispensing press caps for cream, lotion, gel, and liquid bottles. Easy one-handed operation with precise dispensing control. OEM/ODM manufacturing available.', '&lt;h2&gt;ฝากด ฝาพลาสติกแบบกด สำหรับขวดบรรจุภัณฑ์&lt;/h2&gt;\n&lt;p&gt;168 Innovative จำหน่ายและรับผลิต &lt;strong&gt;ฝากด ฝาพลาสติกแบบกด&lt;/strong&gt; คุณภาพสูง สำหรับขวดครีม โลชั่น เจล และของเหลวทุกชนิด ออกแบบมาเพื่อการใช้งานง่ายด้วยมือเดียว ควบคุมปริมาณได้แม่นยำ ไม่หยด&lt;/p&gt;\n&lt;h3&gt;เหมาะสำหรับผลิตภัณฑ์ใดบ้าง?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ครีมบำรุงผิวและ body lotion&lt;/li&gt;\n&lt;li&gt;เจลล้างมือและ hand cream&lt;/li&gt;\n&lt;li&gt;แชมพูและครีมนวดผม&lt;/li&gt;\n&lt;li&gt;ผลิตภัณฑ์ทำความสะอาดในบ้าน&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;จุดเด่น&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ใช้งานง่ายด้วยมือเดียว one-handed operation&lt;/li&gt;\n&lt;li&gt;ควบคุมปริมาณได้แม่นยำ ไม่หยด ไม่เลอะ&lt;/li&gt;\n&lt;li&gt;วัสดุพลาสติกคุณภาพสูง ทนทาน&lt;/li&gt;\n&lt;li&gt;รับผลิต OEM/ODM custom size และสี&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Dispensing Press Caps for Liquid Packaging&lt;/h2&gt;\n&lt;p&gt;168 Innovative supplies and manufactures &lt;strong&gt;dispensing press caps&lt;/strong&gt; for cream, lotion, gel, and liquid bottles. Designed for easy one-handed operation with precise, drip-free dispensing control.&lt;/p&gt;\n&lt;h3&gt;Suitable Products&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Skin cream and body lotion&lt;/li&gt;\n&lt;li&gt;Hand gel and hand cream&lt;/li&gt;\n&lt;li&gt;Shampoo and conditioner&lt;/li&gt;\n&lt;li&gt;Household cleaning products&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;Key Features&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Easy one-handed operation&lt;/li&gt;\n&lt;li&gt;Precise dispensing — drip-free and mess-free&lt;/li&gt;\n&lt;li&gt;High-quality durable plastic&lt;/li&gt;\n&lt;li&gt;OEM/ODM custom size and color available&lt;/li&gt;\n&lt;/ul&gt;', 'ฝากด ฝาพลาสติกแบบกด สำหรับขวด OEM | 168 Innovative', 'Dispensing Press Cap for Bottles OEM Thailand | 168 Innovative', 'ฝากด ฝาพลาสติกแบบกด สำหรับขวดครีม โลชั่น เจล ใช้งานง่าย ควบคุมปริมาณได้แม่นยำ รับผลิต OEM/ODM ส่งทั่วไทย', 'Dispensing press caps for cream, lotion, and gel bottles. One-handed operation with precise output control. OEM/ODM manufacturing in Thailand. Request a quote.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/dispensing-cap.webp', 'ฝากด ฝาพลาสติกแบบกด OEM สำหรับขวดครีมและโลชั่น', 'ฝากด ฝาพลาสติกแบบกด OEM สำหรับขวดครีมและโลชั่น', 6, 1),
  (7, 'lipstick-packaging', 'แพ็กเกจลิปสติก', 'Lipstick Packaging', 'หลอดลิปสติก แพ็กเกจลิปสติก สำหรับแบรนด์เครื่องสำอาง OEM/ODM หลากหลายวัสดุและรูปแบบ ทั้งพลาสติกและอะลูมิเนียม รับผลิตตามแบบ', 'Lipstick tubes and packaging for cosmetic brands. OEM/ODM manufacturing in plastic and aluminum. Custom design available.', '&lt;h2&gt;แพ็กเกจลิปสติก OEM สำหรับแบรนด์เครื่องสำอาง&lt;/h2&gt;\n&lt;p&gt;168 Innovative ผู้ผลิต &lt;strong&gt;หลอดลิปสติก และแพ็กเกจลิปสติก&lt;/strong&gt; คุณภาพสูง สำหรับแบรนด์ OEM/ODM มีทั้งวัสดุพลาสติกและอะลูมิเนียม หลากหลายรูปแบบ เหมาะสำหรับแบรนด์ที่ต้องการความหรูหราหรือ eco-friendly&lt;/p&gt;\n&lt;h3&gt;วัสดุที่มีให้เลือก&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;พลาสติก ABS — น้ำหนักเบา ราคาประหยัด เหมาะสำหรับ mass market&lt;/li&gt;\n&lt;li&gt;อะลูมิเนียม — พรีเมียม ทนทาน เหมาะสำหรับ luxury brand&lt;/li&gt;\n&lt;li&gt;Recycled plastic — เหมาะสำหรับ eco-conscious brand&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;บริการ OEM/ODM&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Custom design ทั้ง shape, size และ mechanism&lt;/li&gt;\n&lt;li&gt;เลือก finish ได้ matte, glossy, metallic&lt;/li&gt;\n&lt;li&gt;พิมพ์โลโก้และ hot stamping&lt;/li&gt;\n&lt;li&gt;MOQ ยืดหยุ่น เหมาะทั้งแบรนด์ใหม่และแบรนด์ใหญ่&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Lipstick Packaging OEM for Cosmetic Brands&lt;/h2&gt;\n&lt;p&gt;168 Innovative manufactures premium &lt;strong&gt;lipstick tubes and packaging&lt;/strong&gt; for OEM/ODM brands. Available in plastic and aluminum — suitable for mass market, luxury, and eco-conscious brands.&lt;/p&gt;\n&lt;h3&gt;Available Materials&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ABS Plastic — lightweight, cost-effective, ideal for mass market&lt;/li&gt;\n&lt;li&gt;Aluminum — premium, durable, ideal for luxury brands&lt;/li&gt;\n&lt;li&gt;Recycled plastic — ideal for eco-conscious brands&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;OEM/ODM Services&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Custom shape, size, and mechanism design&lt;/li&gt;\n&lt;li&gt;Matte, glossy, and metallic finish options&lt;/li&gt;\n&lt;li&gt;Logo printing and hot stamping available&lt;/li&gt;\n&lt;li&gt;Flexible MOQ for new and established brands&lt;/li&gt;\n&lt;/ul&gt;', 'แพ็กเกจลิปสติก หลอดลิปสติก OEM | 168 Innovative', 'Lipstick Packaging & Tube OEM Thailand | 168 Innovative', 'แพ็กเกจลิปสติก หลอดลิปสติก OEM/ODM คุณภาพสูง พลาสติกและอะลูมิเนียม รับผลิตตามแบบสำหรับแบรนด์เครื่องสำอาง สั่งจำนวนมาก', 'Premium lipstick tubes and packaging for OEM/ODM cosmetic brands. Plastic and aluminum options. Custom design manufacturing in Thailand.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/lipstick_bottles.webp', 'แพ็กเกจลิปสติก หลอดลิปสติก OEM สำหรับแบรนด์เครื่องสำอาง', 'Lipstick Packaging Tube OEM for Cosmetic Brands Thailand', 7, 1),
  (8, 'mascara-packaging', 'บรรจุภัณฑ์มาสคาร่า', 'Mascara Packaging', 'หลอดมาสคาร่า บรรจุภัณฑ์มาสคาร่า สำหรับแบรนด์เครื่องสำอาง OEM/ODM คุณภาพสูง หลากหลายรูปแบบและขนาด รับผลิตตามแบบ', 'Mascara tubes and packaging for cosmetic brands. OEM/ODM manufacturing with various styles and sizes. Custom design available.', '&lt;h2&gt;บรรจุภัณฑ์มาสคาร่า OEM สำหรับแบรนด์เครื่องสำอาง&lt;/h2&gt;\n&lt;p&gt;168 Innovative ผู้ผลิต &lt;strong&gt;หลอดมาสคาร่า และบรรจุภัณฑ์มาสคาร่า&lt;/strong&gt; คุณภาพสูงสำหรับแบรนด์ OEM/ODM รับผลิตตามแบบ หลากหลายรูปทรงและขนาด เหมาะสำหรับแบรนด์ใหม่และแบรนด์ที่ต้องการ private label&lt;/p&gt;\n&lt;h3&gt;ประเภทบรรจุภัณฑ์ที่มี&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;หลอดมาสคาร่าแบบมาตรฐาน (Standard Mascara Tube)&lt;/li&gt;\n&lt;li&gt;หลอดมาสคาร่าแบบ slim สำหรับ travel size&lt;/li&gt;\n&lt;li&gt;หลอดพร้อมแปรง wand หลากหลายรูปแบบ&lt;/li&gt;\n&lt;li&gt;Custom design ตามแบบที่ต้องการ&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;บริการ OEM/ODM&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ออกแบบและผลิตตามแบบ&lt;/li&gt;\n&lt;li&gt;เลือกสีและ finish ได้ตาม brand&lt;/li&gt;\n&lt;li&gt;พิมพ์โลโก้และ branding ครบวงจร&lt;/li&gt;\n&lt;li&gt;MOQ ยืดหยุ่น เหมาะทั้งแบรนด์ใหม่และแบรนด์ใหญ่&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Mascara Packaging OEM for Cosmetic Brands&lt;/h2&gt;\n&lt;p&gt;168 Innovative manufactures premium &lt;strong&gt;mascara tubes and packaging&lt;/strong&gt; for OEM/ODM cosmetic brands. Custom design, multiple shapes and sizes available — ideal for new brands and private label products.&lt;/p&gt;\n&lt;h3&gt;Available Packaging Types&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Standard mascara tubes&lt;/li&gt;\n&lt;li&gt;Slim tubes for travel size products&lt;/li&gt;\n&lt;li&gt;Various wand and brush styles&lt;/li&gt;\n&lt;li&gt;Fully custom design on request&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;OEM/ODM Services&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Custom design and mold production&lt;/li&gt;\n&lt;li&gt;Color and finish selection&lt;/li&gt;\n&lt;li&gt;Logo printing and full branding&lt;/li&gt;\n&lt;li&gt;Flexible MOQ for new and established brands&lt;/li&gt;\n&lt;/ul&gt;', 'บรรจุภัณฑ์มาสคาร่า หลอดมาสคาร่า OEM | 168 Innovative', 'Mascara Packaging & Tube OEM Manufacturer Thailand | 168 Innovative', 'บรรจุภัณฑ์มาสคาร่า หลอดมาสคาร่า OEM/ODM คุณภาพสูง สำหรับแบรนด์เครื่องสำอาง หลากหลายรูปแบบ รับผลิตตามแบบ สั่งจำนวนมาก', 'High-quality mascara tubes and packaging for cosmetic OEM/ODM brands. Custom design and manufacturing in Thailand. Multiple styles available.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/mascaras.webp', 'บรรจุภัณฑ์มาสคาร่า หลอดมาสคาร่า OEM สำหรับแบรนด์เครื่องสำอาง', 'Mascara Packaging Tube OEM for Cosmetic Brands Thailand', 8, 1),
  (9, 'powder-compact', 'ตลับแป้ง', 'Compact Powder Case', 'ตลับแป้ง กล่องแป้งพัฟ และบรรจุภัณฑ์เครื่องสำอางสำหรับแป้งอัดแข็ง แป้งพัฟ และไฮไลท์ รับผลิต OEM/ODM สำหรับแบรนด์เครื่องสำอาง', 'Compact powder cases and cosmetic packaging for pressed powder, blush, and highlighter. OEM/ODM manufacturing for cosmetic brands.', '&lt;h2&gt;ตลับแป้ง และบรรจุภัณฑ์เครื่องสำอาง OEM&lt;/h2&gt;\n&lt;p&gt;168 Innovative ผู้ผลิต &lt;strong&gt;ตลับแป้ง กล่องแป้งพัฟ&lt;/strong&gt; และบรรจุภัณฑ์เครื่องสำอางคุณภาพสูง เหมาะสำหรับแบรนด์ที่ต้องการสร้างผลิตภัณฑ์ในนาม OEM/ODM รับผลิตตามแบบ custom design ครบวงจร&lt;/p&gt;\n&lt;h3&gt;เหมาะสำหรับผลิตภัณฑ์ใดบ้าง?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;แป้งอัดแข็ง (Pressed Powder)&lt;/li&gt;\n&lt;li&gt;บลัชออนและไฮไลท์ (Blush / Highlighter)&lt;/li&gt;\n&lt;li&gt;อายแชโดว์พาเลท (Eyeshadow Palette)&lt;/li&gt;\n&lt;li&gt;แป้งพัฟสำหรับเด็กและผู้ใหญ่&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;บริการ OEM/ODM ครบวงจร&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ออกแบบและผลิตตามแบบที่ต้องการ&lt;/li&gt;\n&lt;li&gt;เลือกวัสดุ สี และ finish ได้หลากหลาย&lt;/li&gt;\n&lt;li&gt;รองรับ private label และพิมพ์โลโก้&lt;/li&gt;\n&lt;li&gt;MOQ ยืดหยุ่น เหมาะสำหรับแบรนด์ใหม่และแบรนด์ใหญ่&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Compact Powder Cases &amp; Cosmetic Packaging OEM&lt;/h2&gt;\n&lt;p&gt;168 Innovative manufactures premium &lt;strong&gt;compact powder cases&lt;/strong&gt; and cosmetic packaging for OEM/ODM brands. Custom design, material selection, and private label services available.&lt;/p&gt;\n&lt;h3&gt;Suitable Products&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Pressed Powder Compacts&lt;/li&gt;\n&lt;li&gt;Blush and Highlighter Cases&lt;/li&gt;\n&lt;li&gt;Eyeshadow Palettes&lt;/li&gt;\n&lt;li&gt;Face Powder Compacts&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;OEM/ODM Services&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Custom design and mold production&lt;/li&gt;\n&lt;li&gt;Multiple material, color, and finish options&lt;/li&gt;\n&lt;li&gt;Private label and logo printing&lt;/li&gt;\n&lt;li&gt;Flexible MOQ for new and established brands&lt;/li&gt;\n&lt;/ul&gt;', 'ตลับแป้งพัฟ ตลับแป้ง กล่องแป้ง OEM สำหรับแบรนด์เครื่องสำอาง | 168 Innovative', 'Compact Powder Case OEM Cosmetic Packaging | 168 Innovative', 'ตลับแป้ง กล่องแป้งพัฟ บรรจุภัณฑ์เครื่องสำอาง OEM/ODM คุณภาพสูง เหมาะสำหรับแป้งอัดแข็ง บลัชออน ไฮไลท์ รับผลิตตามแบบ สั่งจำนวนมาก', 'High-quality compact powder cases for pressed powder, blush, and highlighter. OEM/ODM cosmetic packaging manufacturer in Thailand. Custom design available.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/Compact-Powder-Case.webp', 'ตลับแป้ง กล่องแป้งพัฟ OEM สำหรับแบรนด์เครื่องสำอาง', 'Compact Powder Case OEM Cosmetic Packaging Thailand', 9, 1),
  (10, 'soap-bag', 'ถุงสบู่ / ถุงบรรจุภัณฑ์', 'Soap Bag & Packaging', 'ถุงสบู่ ถุงบรรจุสบู่ก้อน และถุงบรรจุภัณฑ์สำหรับผลิตภัณฑ์อาบน้ำ หลากหลายวัสดุ ทั้งผ้า ตาข่าย และพลาสติก รับผลิต OEM ตามแบบ', 'Soap bags and packaging for bath and body products. Available in fabric, mesh, and plastic materials. OEM custom production available.', 'ซองบรรจุสบู่เหลวและผลิตภัณฑ์รีฟิล เหมาะสำหรับสบู่เหลวและผลิตภัณฑ์ดูแลผิว', 'Soap packaging bags for liquid soap and refill products. Ideal for personal care brands.', 'ถุงสบู่ ถุงบรรจุสบู่ OEM หลากหลายวัสดุ | 168 Innovative', 'Soap Bag & Bath Product Packaging OEM Thailand | 168 Innovative', 'ถุงสบู่ ถุงบรรจุสบู่ก้อน สบู่แฮนด์เมด หลากหลายวัสดุ ผ้า ตาข่าย พลาสติก รับผลิต OEM ตามแบบ สั่งจำนวนมาก ราคาส่ง', 'Soap bags and bath product packaging in fabric, mesh, and plastic. OEM custom manufacturing for handmade soap and bath brands. Bulk orders available.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/soap-bags.png', 'ถุงสบู่ / ถุงบรรจุภัณฑ์', 'Soap Packaging Bag', 10, 1),
  (12, 'ball-chain', 'โซ่ลูกปัดและอุปกรณ์เสริม', 'Ball Chain Accessories', 'โซ่ลูกปัด ball chain และอุปกรณ์เสริมสำหรับบรรจุภัณฑ์ สินค้าพรีเมียม ของขวัญ และเครื่องประดับ หลากหลายขนาดและวัสดุ รับผลิต OEM', 'โซ่ลูกปัด ball chain และอุปกรณ์เสริมสำหรับบรรจุภัณฑ์ สินค้าพรีเมียม ของขวัญ และเครื่องประดับ หลากหลายขนาดและวัสดุ รับผลิต OEM', '&lt;h2&gt;โซ่ลูกปัด และอุปกรณ์เสริมบรรจุภัณฑ์&lt;/h2&gt;\n&lt;p&gt;168 Innovative จำหน่าย &lt;strong&gt;โซ่ลูกปัด ball chain&lt;/strong&gt; และอุปกรณ์เสริมสำหรับบรรจุภัณฑ์ สินค้าพรีเมียม ของขวัญ และเครื่องประดับ ช่วยเพิ่มมูลค่าและความน่าสนใจให้กับบรรจุภัณฑ์ของแบรนด์คุณ&lt;/p&gt;\n&lt;h3&gt;การใช้งาน&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;แท็กสินค้าและ price tag&lt;/li&gt;\n&lt;li&gt;พวงกุญแจและจี้บรรจุภัณฑ์&lt;/li&gt;\n&lt;li&gt;ของขวัญและของชำร่วย&lt;/li&gt;\n&lt;li&gt;เครื่องประดับและ accessories&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;จุดเด่น&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;หลากหลายขนาดและความยาว&lt;/li&gt;\n&lt;li&gt;วัสดุโลหะและพลาสติกคุณภาพสูง&lt;/li&gt;\n&lt;li&gt;เพิ่มมูลค่าและ perceived value ให้บรรจุภัณฑ์&lt;/li&gt;\n&lt;li&gt;รับผลิต OEM จำนวนมาก ราคาส่ง&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Ball Chains &amp; Packaging Accessories&lt;/h2&gt;\n&lt;p&gt;168 Innovative supplies &lt;strong&gt;ball chains&lt;/strong&gt; and packaging accessories for premium products, gifts, and jewelry. Add perceived value and visual appeal to your brand\'s packaging.&lt;/p&gt;\n&lt;h3&gt;Applications&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Product tags and price labels&lt;/li&gt;\n&lt;li&gt;Key rings and packaging charms&lt;/li&gt;\n&lt;li&gt;Gift sets and party favors&lt;/li&gt;\n&lt;li&gt;Jewelry and fashion accessories&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;Key Features&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Various sizes and lengths available&lt;/li&gt;\n&lt;li&gt;High-quality metal and plastic materials&lt;/li&gt;\n&lt;li&gt;Adds perceived value to packaging&lt;/li&gt;\n&lt;li&gt;OEM bulk manufacturing at wholesale pricing&lt;/li&gt;\n&lt;/ul&gt;', 'โซ่ลูกปัด Ball Chain อุปกรณ์เสริมบรรจุภัณฑ์ OEM | 168 Innovative', 'Ball Chain & Packaging Accessories OEM Thailand | 168 Innovative', 'โซ่ลูกปัด ball chain อุปกรณ์เสริมสำหรับบรรจุภัณฑ์ สินค้าพรีเมียม ของขวัญ หลากหลายขนาด รับผลิต OEM ส่งทั่วไทย', 'Ball chains and packaging accessories for premium products, gifts, and jewelry. OEM manufacturing in Thailand. Various sizes available. Request a quote.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/ball_chain_cat.webp', 'โซ่ลูกปัด ball chain อุปกรณ์เสริมบรรจุภัณฑ์ OEM', 'Ball Chain Packaging Accessories OEM Thailand', 12, 1),
  (23, 'plastic-handle', 'ที่จับพลาสติก', 'Plastic Handle', 'ที่จับพลาสติก หูหิ้วพลาสติก สำหรับถุง กล่อง และบรรจุภัณฑ์ทุกประเภท ทนทาน น้ำหนักเบา รับผลิต OEM ตามขนาดและสีที่ต้องการ', 'Plastic handles for bags, boxes, and all types of packaging. Durable and lightweight. OEM manufacturing available in custom sizes and colors.', '&lt;h2&gt;ที่จับพลาสติก สำหรับบรรจุภัณฑ์ทุกประเภท&lt;/h2&gt;\n&lt;p&gt;168 Innovative จำหน่ายและรับผลิต &lt;strong&gt;ที่จับพลาสติก หูหิ้วพลาสติก&lt;/strong&gt; คุณภาพสูง สำหรับถุง กล่อง และบรรจุภัณฑ์ทุกประเภท ทนทาน น้ำหนักเบา รับแรงได้ดี เหมาะสำหรับ B2B และแบรนด์ที่ต้องการ packaging ที่ใช้งานง่าย&lt;/p&gt;\n&lt;h3&gt;มีให้เลือกกี่ขนาด?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ขนาด S — เหมาะกับถุงขนาดเล็ก ของชำร่วย gift set&lt;/li&gt;\n&lt;li&gt;ขนาด M — เหมาะกับถุงสินค้าทั่วไป น้ำหนักปานกลาง&lt;/li&gt;\n&lt;li&gt;สั่งผลิต custom size ได้ตามต้องการ&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;จุดเด่น&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;พลาสติกคุณภาพสูง ทนทาน รับน้ำหนักได้ดี&lt;/li&gt;\n&lt;li&gt;น้ำหนักเบา ไม่เพิ่มต้นทุนบรรจุภัณฑ์&lt;/li&gt;\n&lt;li&gt;เลือกสีได้ตาม brand identity&lt;/li&gt;\n&lt;li&gt;รับผลิต OEM จำนวนมาก ราคาส่ง&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Plastic Handles for All Packaging Types&lt;/h2&gt;\n&lt;p&gt;168 Innovative supplies and manufactures &lt;strong&gt;plastic handles&lt;/strong&gt; for bags, boxes, and all packaging types. Durable, lightweight, and load-bearing — ideal for B2B buyers and brands seeking functional packaging.&lt;/p&gt;\n&lt;h3&gt;Available Sizes&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Size S — ideal for small bags, gift sets, and favors&lt;/li&gt;\n&lt;li&gt;Size M — suitable for standard product bags and medium loads&lt;/li&gt;\n&lt;li&gt;Custom sizes available on request&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;Key Features&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;High-quality plastic — durable and load-bearing&lt;/li&gt;\n&lt;li&gt;Lightweight — keeps packaging cost-efficient&lt;/li&gt;\n&lt;li&gt;Custom color options to match brand identity&lt;/li&gt;\n&lt;li&gt;OEM bulk manufacturing at wholesale pricing&lt;/li&gt;\n&lt;/ul&gt;', 'ที่จับพลาสติก หูหิ้ว สำหรับบรรจุภัณฑ์ OEM | 168 Innovative', 'Plastic Handle for Packaging OEM Thailand | 168 Innovative', 'ที่จับพลาสติก หูหิ้วพลาสติก สำหรับถุงและบรรจุภัณฑ์ทุกประเภท ทนทาน น้ำหนักเบา รับผลิต OEM custom size และสี ราคาส่ง', 'Durable plastic handles for bags and packaging. Custom size and color OEM manufacturing available in Thailand. Bulk orders welcome. Request a quote.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/plastic-handle.webp', 'ที่จับพลาสติก หูหิ้วพลาสติกสำหรับบรรจุภัณฑ์ OEM', 'Plastic Handle for Packaging OEM Thailand', 23, 1),
  (999999, 'uncategorized-migrated', 'สินค้ารอจัดหมวด', 'Uncategorized Migrated Products', 'หมวดชั่วคราวสำหรับสินค้าที่มีอยู่ใน WordPress dump แต่ยังไม่ได้ผูก product_category', 'Temporary category for products found in the WordPress dump without a mapped product_category relation.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 999999, 1);
INSERT INTO `products` (`id`, `category_id`, `slug`, `name_th`, `name_en`, `family_name_th`, `family_name_en`, `description_th`, `description_en`, `content_th`, `content_en`, `application_th`, `application_en`, `seo_title_th`, `seo_title_en`, `seo_description_th`, `seo_description_en`, `image_url`, `image_alt_th`, `image_alt_en`, `sku`, `availability_status`, `moq`, `lead_time`, `default_variant_slug`, `sort_order`, `is_published`) VALUES
  (463, 5, 'plastic-spout-hl018-1-8mm', 'จุกพลาสติก HL018 ขนาด 1.8 มม.', 'Plastic Spout HL018 1.8mm', NULL, NULL, 'จุกพลาสติก HL018 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 1.8 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการควบคุมปริมาณของเหลวอย่างแม่นยำ จุกขนาดเล็กพิเศษนี้ออกแบบมาเพื่อรองรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch สำหรับผลิตภัณฑ์ความหนืดสูง วัสดุ PE ที่ใช้ผลิตมีความยืดหยุ่น ทนทานต่อสารเคมี และปลอดภัยสำหรับการสัมผัสกับผลิตภัณฑ์ดูแลผิว เจล และของเหลวเข้มข้น เหมาะกับอุตสาหกรรมเครื่องสำอาง ยา และผลิตภัณฑ์ดูแลส่วนตัว ตอบโจทย์ผู้ผลิตที่ต้องการบรรจุภัณฑ์มาตรฐานสูงในราคาที่แข่งขันได้', 'The HL018 plastic spout features an ultra-small inner diameter of 1.8mm, manufactured from high-quality PE material suitable for precision liquid dispensing in cosmetic and beauty packaging. This small-size spout cap is ideal for refill pouches, liquid pouch packaging, and cosmetic applications where controlled flow is essential. The PE construction ensures chemical resistance, flexibility, and compatibility with a wide range of beauty formulations including serums, gels, and concentrated liquids. Designed for B2B packaging suppliers and cosmetic manufacturers seeking reliable, high-precision spout solutions, the HL018 meets stringent quality standards for personal care and pharmaceutical pouch packaging. Its compact design makes it a preferred choice for travel-size and sample packaging formats.', '<p>จุกพลาสติก HL018 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 1.8 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการควบคุมปริมาณของเหลวอย่างแม่นยำ จุกขนาดเล็กพิเศษนี้ออกแบบมาเพื่อรองรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch สำหรับผลิตภัณฑ์ความหนืดสูง วัสดุ PE ที่ใช้ผลิตมีความยืดหยุ่น ทนทานต่อสารเคมี และปลอดภัยสำหรับการสัมผัสกับผลิตภัณฑ์ดูแลผิว เจล และของเหลวเข้มข้น เหมาะกับอุตสาหกรรมเครื่องสำอาง ยา และผลิตภัณฑ์ดูแลส่วนตัว ตอบโจทย์ผู้ผลิตที่ต้องการบรรจุภัณฑ์มาตรฐานสูงในราคาที่แข่งขันได้</p>', '<p>The HL018 plastic spout features an ultra-small inner diameter of 1.8mm, manufactured from high-quality PE material suitable for precision liquid dispensing in cosmetic and beauty packaging. This small-size spout cap is ideal for refill pouches, liquid pouch packaging, and cosmetic applications where controlled flow is essential. The PE construction ensures chemical resistance, flexibility, and compatibility with a wide range of beauty formulations including serums, gels, and concentrated liquids. Designed for B2B packaging suppliers and cosmetic manufacturers seeking reliable, high-precision spout solutions, the HL018 meets stringent quality standards for personal care and pharmaceutical pouch packaging. Its compact design makes it a preferred choice for travel-size and sample packaging formats.</p>', 'บรรจุภัณฑ์เครื่องสำอาง, บรรจุภัณฑ์ความงาม, ซองบรรจุของเหลว, ซองรีฟิล', 'Cosmetic Packaging, Beauty Packaging, Liquid Pouch, Refill Pouch', 'จุกพลาสติก HL018 ขนาด 1.8 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL018 1.8mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL018 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 1.8 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการควบคุมปริมาณของเหลวอย่างแม่นยำ จุกขนาดเล็กพิเศษนี้ออกแบบมาเพื่อรองรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch สำหรับผลิตภัณฑ์ความหนืดสูง วัสดุ PE ที่ใช้ผลิตมีความยืดหยุ่น ทนทานต่อสารเคมี และปลอดภัยสำหรับการสัมผัสกับผลิตภัณฑ์ดูแลผิว เจล และของเหลวเข้มข้น เหมาะกับอุตสาหกรรมเครื่องสำอาง ยา และผลิตภัณฑ์ดูแลส่วนตัว ตอบโจทย์ผู้ผลิตที่ต้องการบรรจุภัณฑ์มาตรฐานสูงในราคาที่แข่งขันได้ รุ่น HL018 ขนาด 1.8 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL018 plastic spout features an ultra-small inner diameter of 1.8mm, manufactured from high-quality PE material suitable for precision liquid dispensin...', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL018.jpg', 'จุกพลาสติก HL018 ขนาด 1.8 มม. PE สำหรับซองเครื่องสำอาง', 'Plastic Spout HL018 1.8mm PE for Cosmetic Pouch Packaging', NULL, NULL, NULL, NULL, NULL, 463, 1),
  (464, 5, 'plastic-spout-hl020-2mm', 'จุกพลาสติก HL020 ขนาด 2 มม.', 'Plastic Spout HL020 2mm', NULL, NULL, 'จุกพลาสติก HL020 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 2 มม. ออกแบบมาสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการจ่ายของเหลวในปริมาณน้อยและแม่นยำ เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ใช้ในอุตสาหกรรมความงามและการดูแลส่วนตัว วัสดุ PE มีความทนทานสูง ปลอดภัยต่อการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท และสามารถผลิตในปริมาณมากได้ตามมาตรฐานอุตสาหกรรม เหมาะสำหรับผู้ผลิตบรรจุภัณฑ์ที่ต้องการโซลูชั่นคุณภาพสูงในราคาที่เหมาะสม', 'The HL020 plastic spout cap with a 2mm inner diameter is crafted from premium PE material, delivering precise liquid dispensing for cosmetic and beauty packaging applications. This small-size spout is engineered for refill pouch packaging, liquid pouches, and beauty product containers requiring fine flow control. The PE material provides excellent chemical resistance and durability, making it compatible with serums, essences, and other personal care formulations. Ideal for B2B cosmetic packaging suppliers and contract manufacturers, the HL020 offers consistent performance in high-volume production environments. Its compact design suits sample pouches, travel-size packaging, and precision dosage applications across cosmetic, pharmaceutical, and personal care industries.', '<p>จุกพลาสติก HL020 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 2 มม. ออกแบบมาสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการจ่ายของเหลวในปริมาณน้อยและแม่นยำ เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ใช้ในอุตสาหกรรมความงามและการดูแลส่วนตัว วัสดุ PE มีความทนทานสูง ปลอดภัยต่อการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท และสามารถผลิตในปริมาณมากได้ตามมาตรฐานอุตสาหกรรม เหมาะสำหรับผู้ผลิตบรรจุภัณฑ์ที่ต้องการโซลูชั่นคุณภาพสูงในราคาที่เหมาะสม</p>', '<p>The HL020 plastic spout cap with a 2mm inner diameter is crafted from premium PE material, delivering precise liquid dispensing for cosmetic and beauty packaging applications. This small-size spout is engineered for refill pouch packaging, liquid pouches, and beauty product containers requiring fine flow control. The PE material provides excellent chemical resistance and durability, making it compatible with serums, essences, and other personal care formulations. Ideal for B2B cosmetic packaging suppliers and contract manufacturers, the HL020 offers consistent performance in high-volume production environments. Its compact design suits sample pouches, travel-size packaging, and precision dosage applications across cosmetic, pharmaceutical, and personal care industries.</p>', 'บรรจุภัณฑ์เครื่องสำอาง, บรรจุภัณฑ์ความงาม, ซองบรรจุของเหลว, ซองรีฟิล', 'Cosmetic Packaging, Beauty Packaging, Liquid Pouch, Refill Pouch', 'จุกพลาสติก HL020 ขนาด 2 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL020 2mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL020 ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 2 มม. ออกแบบมาสำหรับบรรจุภัณฑ์เครื่องสำอางและผลิตภัณฑ์ความงามที่ต้องการการจ่ายของเหลวในปริมาณน้อยและแม่นยำ เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ใช้ในอุตสาหกรรมความงามและการดูแลส่วนตัว วัสดุ PE มีความทนทานสูง ปลอดภัยต่อการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท และสามารถผลิตในปริมาณมากได้ตามมาตรฐานอุตสาหกรรม เหมาะสำหรับผู้ผลิตบรรจุภัณฑ์ที่ต้องการโซลูชั่นคุณภาพสูงในราคาที่เหมาะสม รุ่น HL020 ขนาด 2 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL020 plastic spout cap with a 2mm inner diameter is crafted from premium PE material, delivering precise liquid dispensing for cosmetic and beauty pac...', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL020.jpg', 'จุกพลาสติก HL020 ขนาด 2 มม. PE สำหรับบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL020 2mm PE for Cosmetic and Beauty Packaging', NULL, NULL, NULL, NULL, NULL, 464, 1),
  (465, 5, 'plastic-spout-hl050-5mm', 'จุกพลาสติก HL050 ขนาด 5 มม.', 'Plastic Spout HL050 5mm', NULL, NULL, 'จุกพลาสติก HL050 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะอย่างยิ่งสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวในอุตสาหกรรมความงาม ขนาด 5 มม. ช่วยให้การไหลของของเหลวมีความสม่ำเสมอและควบคุมได้ง่าย เหมาะสำหรับโลชั่น ครีม เซรั่ม และผลิตภัณฑ์ของเหลวที่มีความหนืดปานกลาง วัสดุ PE ทนทานต่อสารเคมีและอุณหภูมิหลากหลาย ตอบสนองความต้องการของผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการบรรจุภัณฑ์มาตรฐานสูงและผลิตได้ในปริมาณมาก', 'The HL050 plastic spout with a 5mm inner diameter is made from high-quality PE material, offering reliable liquid flow for cosmetic, beauty, and personal care packaging. This versatile spout cap suits a wide range of liquid pouch applications including lotions, creams, serums, and refill packaging products. The PE construction ensures chemical compatibility and structural durability across various formulations. Designed for industrial B2B packaging production, the HL050 is a popular choice for cosmetic brands and contract fillers requiring consistent performance in high-volume manufacturing. Its 5mm opening delivers smooth dispensing suitable for medium-viscosity liquids, making it a go-to solution for modern flexible pouch packaging.', '<p>จุกพลาสติก HL050 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะอย่างยิ่งสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวในอุตสาหกรรมความงาม ขนาด 5 มม. ช่วยให้การไหลของของเหลวมีความสม่ำเสมอและควบคุมได้ง่าย เหมาะสำหรับโลชั่น ครีม เซรั่ม และผลิตภัณฑ์ของเหลวที่มีความหนืดปานกลาง วัสดุ PE ทนทานต่อสารเคมีและอุณหภูมิหลากหลาย ตอบสนองความต้องการของผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการบรรจุภัณฑ์มาตรฐานสูงและผลิตได้ในปริมาณมาก</p>', '<p>The HL050 plastic spout with a 5mm inner diameter is made from high-quality PE material, offering reliable liquid flow for cosmetic, beauty, and personal care packaging. This versatile spout cap suits a wide range of liquid pouch applications including lotions, creams, serums, and refill packaging products. The PE construction ensures chemical compatibility and structural durability across various formulations. Designed for industrial B2B packaging production, the HL050 is a popular choice for cosmetic brands and contract fillers requiring consistent performance in high-volume manufacturing. Its 5mm opening delivers smooth dispensing suitable for medium-viscosity liquids, making it a go-to solution for modern flexible pouch packaging.</p>', 'บรรจุภัณฑ์เครื่องสำอาง, ซองบรรจุของเหลว, ซองรีฟิล, ผลิตภัณฑ์ดูแลส่วนตัว', 'Cosmetic Packaging, Liquid Pouch, Refill Pouch, Personal Care', 'จุกพลาสติก HL050 ขนาด 5 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL050 5mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL050 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะอย่างยิ่งสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลวในอุตสาหกรรมความงาม ขนาด 5 มม. ช่วยให้การไหลของของเหลวมีความสม่ำเสมอและควบคุมได้ง่าย เหมาะสำหรับโลชั่น ครีม เซรั่ม และผลิตภัณฑ์ของเหลวที่มีความหนืดปานกลาง วัสดุ PE ทนทานต่อสารเคมีและอุณหภูมิหลากหลาย ตอบสนองความต้องการของผู้ผลิตในอุตสาหกรรม B2B ที่ต้องการบรรจุภัณฑ์มาตรฐานสูงและผลิตได้ในปริมาณมาก รุ่น HL050 ขนาด 5 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL050 plastic spout with a 5mm inner diameter is made from high-quality PE material, offering reliable liquid flow for cosmetic, beauty, and personal c...', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL050.jpg', 'จุกพลาสติก HL050 ขนาด 5 มม. PE สำหรับซองรีฟิลและบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL050 5mm PE for Refill Pouch and Cosmetic Packaging', NULL, NULL, NULL, NULL, NULL, 465, 1),
  (466, 5, 'plastic-spout-h055w-5mm-ldpe', 'จุกพลาสติก H055W ขนาด 5 มม. LDPE', 'Plastic Spout H055W 5mm LDPE', NULL, NULL, 'จุกพลาสติก H055W ผลิตจาก LDPE (Low-Density Polyethylene) มีเส้นผ่านศูนย์กลางภายใน 5 มม. วัสดุ LDPE มีความยืดหยุ่นสูงกว่า PE ทั่วไป เหมาะสำหรับบรรจุภัณฑ์ที่ต้องการความนุ่มนวลในการบีบและการจ่ายผลิตภัณฑ์ ใช้งานได้หลากหลายทั้งในอุตสาหกรรมเครื่องสำอาง อาหาร และผลิตภัณฑ์ดูแลส่วนตัว เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ต้องการวัสดุที่มีความยืดหยุ่นและทนทาน H055W เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับผู้ผลิตที่ต้องการคุณภาพสูงและการใช้งานที่หลากหลาย', 'The H055W plastic spout is manufactured from LDPE (Low-Density Polyethylene) with a 5mm inner diameter, offering superior flexibility compared to standard PE spouts. The LDPE material provides excellent squeeze performance, making it ideal for cosmetic, food, and personal care liquid pouch packaging where soft dispensing is required. This spout cap is well-suited for refill pouches, squeeze tubes, and flexible packaging formats used across the beauty, food, and household product industries. Designed for B2B packaging manufacturers, the H055W delivers consistent sealing and dispensing performance in high-volume production. Its flexible LDPE construction ensures compatibility with a broad spectrum of liquid formulations.', '<p>จุกพลาสติก H055W ผลิตจาก LDPE (Low-Density Polyethylene) มีเส้นผ่านศูนย์กลางภายใน 5 มม. วัสดุ LDPE มีความยืดหยุ่นสูงกว่า PE ทั่วไป เหมาะสำหรับบรรจุภัณฑ์ที่ต้องการความนุ่มนวลในการบีบและการจ่ายผลิตภัณฑ์ ใช้งานได้หลากหลายทั้งในอุตสาหกรรมเครื่องสำอาง อาหาร และผลิตภัณฑ์ดูแลส่วนตัว เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ต้องการวัสดุที่มีความยืดหยุ่นและทนทาน H055W เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับผู้ผลิตที่ต้องการคุณภาพสูงและการใช้งานที่หลากหลาย</p>', '<p>The H055W plastic spout is manufactured from LDPE (Low-Density Polyethylene) with a 5mm inner diameter, offering superior flexibility compared to standard PE spouts. The LDPE material provides excellent squeeze performance, making it ideal for cosmetic, food, and personal care liquid pouch packaging where soft dispensing is required. This spout cap is well-suited for refill pouches, squeeze tubes, and flexible packaging formats used across the beauty, food, and household product industries. Designed for B2B packaging manufacturers, the H055W delivers consistent sealing and dispensing performance in high-volume production. Its flexible LDPE construction ensures compatibility with a broad spectrum of liquid formulations.</p>', 'บรรจุภัณฑ์เครื่องสำอาง, บรรจุภัณฑ์อาหาร, ซองบรรจุของเหลว, ซองรีฟิล, ผลิตภัณฑ์ดูแลส่วนตัว', 'Cosmetic Packaging, Food Packaging, Liquid Pouch, Refill Pouch, Personal Care', 'จุกพลาสติก H055W ขนาด 5 มม. LDPE | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout H055W 5mm LDPE | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก H055W ผลิตจาก LDPE (Low-Density Polyethylene) มีเส้นผ่านศูนย์กลางภายใน 5 มม. วัสดุ LDPE มีความยืดหยุ่นสูงกว่า PE ทั่วไป เหมาะสำหรับบรรจุภัณฑ์ที่ต้องการความนุ่มนวลในการบีบและการจ่ายผลิตภัณฑ์ ใช้งานได้หลากหลายทั้งในอุตสาหกรรมเครื่องสำอาง อาหาร และผลิตภัณฑ์ดูแลส่วนตัว เหมาะสำหรับซองรีฟิล ซองบรรจุของเหลว และบรรจุภัณฑ์แบบ pouch ที่ต้องการวัสดุที่มีความยืดหยุ่นและทนทาน H055W เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับผู้ผลิตที่ต้องการคุณภาพสูงและการใช้งานที่หลากหลาย รุ่น H055W ขนาด 5 มม. วัสดุ LDPE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The H055W plastic spout is manufactured from LDPE (Low-Density Polyethylene) with a 5mm inner diameter, offering superior flexibility compared to standard...', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/H055W.jpg', 'จุกพลาสติก H055W ขนาด 5 มม. LDPE สำหรับซองบรรจุของเหลว', 'Plastic Spout H055W 5mm LDPE for Liquid Pouch Packaging', NULL, NULL, NULL, NULL, NULL, 466, 1),
  (467, 5, 'plastic-spout-hl055d-1-5mm', 'จุกพลาสติก HL055D-1 ขนาด 5 มม.', 'Plastic Spout HL055D-1 5mm', NULL, NULL, 'จุกพลาสติก HL055D-1 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ความงาม และซองรีฟิลของเหลว รุ่น D-1 มีการออกแบบพิเศษที่เพิ่มประสิทธิภาพการปิดผนึกและการจ่ายผลิตภัณฑ์ เหมาะสำหรับโลชั่น เจล ครีม และผลิตภัณฑ์ของเหลวที่ใช้ในซองแบบ flexible pouch วัสดุ PE ช่วยให้มีความทนทานและความปลอดภัยในการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท เป็นตัวเลือกที่เชื่อถือได้สำหรับผู้ผลิตในอุตสาหกรรม B2B', 'The HL055D-1 plastic spout cap features a 5mm inner diameter and is made from quality PE material, designed for cosmetic, beauty, and liquid pouch packaging applications. The D-1 design variant offers enhanced sealing performance and dispensing reliability, making it suitable for lotions, gels, creams, and various liquid formulations in flexible pouch formats. This spout is a dependable choice for B2B packaging suppliers and cosmetic manufacturers who require consistent quality in large-scale production runs. PE material ensures compatibility with diverse cosmetic and personal care formulations while maintaining structural integrity during filling, sealing, and distribution.', '<p>จุกพลาสติก HL055D-1 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ความงาม และซองรีฟิลของเหลว รุ่น D-1 มีการออกแบบพิเศษที่เพิ่มประสิทธิภาพการปิดผนึกและการจ่ายผลิตภัณฑ์ เหมาะสำหรับโลชั่น เจล ครีม และผลิตภัณฑ์ของเหลวที่ใช้ในซองแบบ flexible pouch วัสดุ PE ช่วยให้มีความทนทานและความปลอดภัยในการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท เป็นตัวเลือกที่เชื่อถือได้สำหรับผู้ผลิตในอุตสาหกรรม B2B</p>', '<p>The HL055D-1 plastic spout cap features a 5mm inner diameter and is made from quality PE material, designed for cosmetic, beauty, and liquid pouch packaging applications. The D-1 design variant offers enhanced sealing performance and dispensing reliability, making it suitable for lotions, gels, creams, and various liquid formulations in flexible pouch formats. This spout is a dependable choice for B2B packaging suppliers and cosmetic manufacturers who require consistent quality in large-scale production runs. PE material ensures compatibility with diverse cosmetic and personal care formulations while maintaining structural integrity during filling, sealing, and distribution.</p>', 'บรรจุภัณฑ์เครื่องสำอาง, บรรจุภัณฑ์ความงาม, ซองบรรจุของเหลว, ซองรีฟิล', 'Cosmetic Packaging, Beauty Packaging, Liquid Pouch, Refill Pouch', 'จุกพลาสติก HL055D-1 ขนาด 5 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL055D-1 5mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL055D-1 ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ความงาม และซองรีฟิลของเหลว รุ่น D-1 มีการออกแบบพิเศษที่เพิ่มประสิทธิภาพการปิดผนึกและการจ่ายผลิตภัณฑ์ เหมาะสำหรับโลชั่น เจล ครีม และผลิตภัณฑ์ของเหลวที่ใช้ในซองแบบ flexible pouch วัสดุ PE ช่วยให้มีความทนทานและความปลอดภัยในการสัมผัสกับผลิตภัณฑ์หลากหลายประเภท เป็นตัวเลือกที่เชื่อถือได้สำหรับผู้ผลิตในอุตสาหกรรม B2B รุ่น HL055D-1 ขนาด 5 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL055D-1 plastic spout cap features a 5mm inner diameter and is made from quality PE material, designed for cosmetic, beauty, and liquid pouch packagin...', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL055D-1.jpg', 'จุกพลาสติก HL055D-1 ขนาด 5 มม. PE สำหรับบรรจุภัณฑ์เครื่องสำอาง', 'Plastic Spout HL055D-1 5mm PE for Cosmetic Liquid Pouch', NULL, NULL, NULL, NULL, NULL, 467, 1),
  (468, 5, 'plastic-spout-hl050d-5mm', 'จุกพลาสติก HL050D ขนาด 5 มม.', 'Plastic Spout HL050D 5mm', NULL, NULL, 'จุกพลาสติก HL050D ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. รุ่น D มีโครงสร้างที่แข็งแรงและออกแบบมาเพื่อการใช้งานในบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์ที่ต้องการจุกปิดที่มั่นคงและการจ่ายของเหลวที่แม่นยำ PE ให้ความทนทานและความปลอดภัยในการสัมผัสกับสารเคมีในผลิตภัณฑ์ความงาม ตอบโจทย์ผู้ผลิตในอุตสาหกรรมบรรจุภัณฑ์ B2B ที่ต้องการคุณภาพและความน่าเชื่อถือในการผลิตปริมาณมาก', 'The HL050D plastic spout with a 5mm inner diameter is made from PE material, featuring a robust design suited for cosmetic, skincare, and liquid pouch packaging. The D-series construction provides a secure seal and controlled liquid dispensing, ideal for a variety of beauty and personal care products in flexible pouch formats. PE material ensures excellent chemical resistance and safety for contact with cosmetic formulations. This spout cap is a reliable solution for B2B packaging manufacturers requiring consistent quality and performance in bulk production environments, covering applications from refill packaging to single-use cosmetic pouches.', '<p>จุกพลาสติก HL050D ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. รุ่น D มีโครงสร้างที่แข็งแรงและออกแบบมาเพื่อการใช้งานในบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์ที่ต้องการจุกปิดที่มั่นคงและการจ่ายของเหลวที่แม่นยำ PE ให้ความทนทานและความปลอดภัยในการสัมผัสกับสารเคมีในผลิตภัณฑ์ความงาม ตอบโจทย์ผู้ผลิตในอุตสาหกรรมบรรจุภัณฑ์ B2B ที่ต้องการคุณภาพและความน่าเชื่อถือในการผลิตปริมาณมาก</p>', '<p>The HL050D plastic spout with a 5mm inner diameter is made from PE material, featuring a robust design suited for cosmetic, skincare, and liquid pouch packaging. The D-series construction provides a secure seal and controlled liquid dispensing, ideal for a variety of beauty and personal care products in flexible pouch formats. PE material ensures excellent chemical resistance and safety for contact with cosmetic formulations. This spout cap is a reliable solution for B2B packaging manufacturers requiring consistent quality and performance in bulk production environments, covering applications from refill packaging to single-use cosmetic pouches.</p>', 'บรรจุภัณฑ์เครื่องสำอาง, ซองบรรจุของเหลว, ซองรีฟิล, ผลิตภัณฑ์ดูแลส่วนตัว', 'Cosmetic Packaging, Liquid Pouch, Refill Pouch, Personal Care', 'จุกพลาสติก HL050D ขนาด 5 มม. | สำหรับซองเครื่องสำอาง | OEM', 'Plastic Spout HL050D 5mm | Cosmetic Packaging OEM / ODM', 'จุกพลาสติก HL050D ผลิตจากวัสดุ PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 5 มม. รุ่น D มีโครงสร้างที่แข็งแรงและออกแบบมาเพื่อการใช้งานในบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองรีฟิลของเหลว เหมาะสำหรับผลิตภัณฑ์ที่ต้องการจุกปิดที่มั่นคงและการจ่ายของเหลวที่แม่นยำ PE ให้ความทนทานและความปลอดภัยในการสัมผัสกับสารเคมีในผลิตภัณฑ์ความงาม ตอบโจทย์ผู้ผลิตในอุตสาหกรรมบรรจุภัณฑ์ B2B ที่ต้องการคุณภาพและความน่าเชื่อถือในการผลิตปริมาณมาก รุ่น HL050D ขนาด 5 มม. วัสดุ PE พร้อมบริการ OEM / ODM ครบวงจร สั่งผลิตตามแบบ รับผลิตจำนวนมาก', 'The HL050D plastic spout with a 5mm inner diameter is made from PE material, featuring a robust design suited for cosmetic, skincare, and liquid pouch pack...', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL050D.jpg', 'จุกพลาสติก HL050D ขนาด 5 มม. PE สำหรับซองรีฟิลและเครื่องสำอาง', 'Plastic Spout HL050D 5mm PE for Refill Pouch and Cosmetic Packaging', NULL, NULL, NULL, NULL, NULL, 468, 1),
  (469, 999999, 'plastic-spout-hl060l-6mm', 'จุกพลาสติก HL060L ขนาด 6 มม.', 'Plastic Spout HL060L 6mm', NULL, NULL, 'จุกพลาสติก HL060L ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 6 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองบรรจุของเหลวที่ต้องการอัตราการไหลที่ดีขึ้น รุ่น L มีการออกแบบโครงสร้างที่รองรับการใช้งานอเนกประสงค์ทั้งในอุตสาหกรรมความงาม อาหาร และผลิตภัณฑ์เพื่อครัวเรือน ขนาด 6 มม. ช่วยให้การจ่ายของเหลวมีความคล่องตัวมากขึ้น เหมาะสำหรับผลิตภัณฑ์ที่มีความหนืดปานกลางถึงต่ำ เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับซองรีฟิลและบรรจุภัณฑ์แบบ flexible pouch', 'The HL060L plastic spout cap with a 6mm inner diameter is manufactured from PE material, designed for cosmetic, food, and household liquid pouch packaging where a slightly larger flow rate is needed. The L-series design provides structural versatility for various flexible pouch applications, including refill packaging, personal care products, and food-grade liquid dispensing. PE material ensures durability and broad chemical compatibility, making the HL060L a dependable choice for B2B packaging suppliers. The 6mm opening offers smooth dispensing for low-to-medium viscosity liquids, supporting efficient filling and consumer-friendly use across multiple industries.', '<p>จุกพลาสติก HL060L ผลิตจาก PE คุณภาพสูง มีเส้นผ่านศูนย์กลางภายใน 6 มม. เหมาะสำหรับบรรจุภัณฑ์เครื่องสำอาง ผลิตภัณฑ์ดูแลผิว และซองบรรจุของเหลวที่ต้องการอัตราการไหลที่ดีขึ้น รุ่น L มีการออกแบบโครงสร้างที่รองรับการใช้งานอเนกประสงค์ทั้งในอุตสาหกรรมความงาม อาหาร และผลิตภัณฑ์เพื่อครัวเรือน ขนาด 6 มม. ช่วยให้การจ่ายของเหลวมีความคล่องตัวมากขึ้น เหมาะสำหรับผลิตภัณฑ์ที่มีความหนืดปานกลางถึงต่ำ เป็นตัวเลือกที่ได้รับความนิยมในอุตสาหกรรม B2B สำหรับซองรีฟิลและบรรจุภัณฑ์แบบ flexible pouch</p>', '<p>The HL060L plastic spout cap with a 6mm inner diameter is manufactured from PE material, designed for cosmetic, food, and household liquid pouch packaging where a slightly larger flow rate is needed. The L-series design provides structural 